import type { HandbookDocumentContent } from "../types";

const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">CAREER · SYSTEM PROJECT</div>\n  <div class=\"nav-title\">시스템 설계 · 프로젝트 심층</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>학습 로드맵</a>\n  <a href=\"#career-readiness-gate\"><span class=\"code\">GATE</span>답변 준비도</a>\n  <a href=\"#career-answer-rubric\"><span class=\"code\">RUBRIC</span>답변 품질</a>\n  <a href=\"#career-pressure-loop\"><span class=\"code\">LOOP</span>압박 대응</a>\n  <a href=\"#career-evidence-packet\"><span class=\"code\">EVIDENCE</span>증거 패킷</a>\n  <a href=\"#career-output-packet\"><span class=\"code\">OUTPUT</span>답변 산출물</a>\n  <a href=\"#career-final-drill\"><span class=\"code\">DRILL</span>최종 점검</a>\n  <a href=\"#doc-system\"><span class=\"code\">DOC</span>시스템 설계 면접</a>\n  <a href=\"#doc-project\"><span class=\"code\">DOC</span>프로젝트 심층 면접</a>\n  <a href=\"#doc-personalfull\"><span class=\"code\">DOC</span>풀스택 개발자 대응</a>\n  <a href=\"#doc-system\"><span class=\"code\">PART</span>시스템 설계 면접</a>\n<a href=\"#system-ch1\"><span class=\"code\">SD-00</span>답변 흐름</a>\n  <a href=\"#system-q1\"><span class=\"code\">SD-01</span>관리자 대시보드</a>\n  <a href=\"#system-q2\"><span class=\"code\">SD-02</span>대형 Data Grid</a>\n  <a href=\"#system-q3\"><span class=\"code\">SD-03</span>실시간 대시보드</a>\n  <a href=\"#system-q4\"><span class=\"code\">SD-04</span>복잡한 폼</a>\n  <a href=\"#system-q5\"><span class=\"code\">SD-05</span>인증 기반 앱</a>\n  <a href=\"#system-q6\"><span class=\"code\">SD-06</span>Excel 업로드</a>\n  <a href=\"#system-q7\"><span class=\"code\">SD-07</span>무한 스크롤 피드</a>\n  <a href=\"#system-q8\"><span class=\"code\">SD-08</span>운영 장애 복구 도구</a>\n  <a href=\"#system-q9\"><span class=\"code\">SD-09</span>다국어 서비스</a>\n  <a href=\"#system-ch2\"><span class=\"code\">SD-10</span>화이트보드 진행 순서</a>\n  <a href=\"#system-ch3\"><span class=\"code\">SD-11</span>Capacity estimation</a>\n  <a href=\"#system-ch4\"><span class=\"code\">SD-12</span>고가용성·DR</a>\n  <a href=\"#system-ch5\"><span class=\"code\">SD-13</span>설계 리뷰 게이트</a>\n  <a href=\"#system-ch6\"><span class=\"code\">SD-14</span>Trade-off Matrix</a>\n  <a href=\"#system-ch7\"><span class=\"code\">SD-15</span>Pressure Drill</a>\n  <a href=\"#system-ch8\"><span class=\"code\">SD-16</span>핵심 질문 20선</a>\n  <a href=\"#system-ch9\"><span class=\"code\">SD-17</span>개념 인과관계</a>\n  <a href=\"#system-ch10\"><span class=\"code\">SD-18</span>완성형 설계 사례</a>\n  <a href=\"#system-system-design-deep-answer-upgrade\"><span class=\"code\">SD-19</span>Deep Answer Model</a>\n  <a href=\"#doc-project\"><span class=\"code\">PART</span>프로젝트 심층 면접</a>\n<a href=\"#project-q1\"><span class=\"code\">PJ-01</span>복잡했던 프로젝트</a>\n  <a href=\"#project-q2\"><span class=\"code\">PJ-02</span>Data Grid·Excel·Validation</a>\n  <a href=\"#project-q3\"><span class=\"code\">PJ-03</span>Flow Editor</a>\n  <a href=\"#project-q4\"><span class=\"code\">PJ-04</span>API 전환</a>\n  <a href=\"#project-q5\"><span class=\"code\">PJ-05</span>운영 이슈 디버깅</a>\n  <a href=\"#project-q6\"><span class=\"code\">PJ-06</span>B2B 도메인 학습</a>\n  <a href=\"#project-q7\"><span class=\"code\">PJ-07</span>Column Definition</a>\n  <a href=\"#project-q8\"><span class=\"code\">PJ-08</span>Validation UX</a>\n  <a href=\"#project-q9\"><span class=\"code\">PJ-09</span>React Flow 성능</a>\n  <a href=\"#project-q10\"><span class=\"code\">PJ-10</span>파일 업로드·다운로드</a>\n  <a href=\"#project-q11\"><span class=\"code\">PJ-11</span>i18n·Storybook</a>\n  <a href=\"#project-q12\"><span class=\"code\">PJ-12</span>백엔드 질문 대응</a>\n  <a href=\"#project-q13\"><span class=\"code\">PJ-13</span>프로젝트 답변 템플릿</a>\n  <a href=\"#project-q14\"><span class=\"code\">PJ-14</span>실제 샘플 답변</a>\n  <a href=\"#project-q15\"><span class=\"code\">PJ-15</span>깊이 증거 장부</a>\n  <a href=\"#project-q16\"><span class=\"code\">PJ-16</span>핵심 질문 20선</a>\n  <a href=\"#project-q17\"><span class=\"code\">PJ-17</span>Evidence Rubric</a>\n  <a href=\"#project-q18\"><span class=\"code\">PJ-18</span>개념 인과관계</a>\n  <a href=\"#project-project-deep-answer-upgrade\"><span class=\"code\">PJ-19</span>Deep Answer Model</a>\n  <a href=\"#doc-personalfull\"><span class=\"code\">PART</span>풀스택 개발자 대응</a>\n<a href=\"#personalfull-ch1\"><span class=\"code\">FS-PER-00</span>전략</a>\n  <a href=\"#personalfull-ch2\"><span class=\"code\">FS-PER-01</span>서버 경계 경험</a>\n  <a href=\"#personalfull-ch3\"><span class=\"code\">FS-PER-02</span>답변 템플릿</a>\n  <a href=\"#personalfull-ch4\"><span class=\"code\">FS-PER-03</span>위험한 표현</a>\n  <a href=\"#personalfull-ch5\"><span class=\"code\">FS-PER-04</span>학습 연결</a>\n  <a href=\"#personalfull-ch6\"><span class=\"code\">FS-PER-05</span>강점 전환 문장</a>\n  <a href=\"#personalfull-ch7\"><span class=\"code\">FS-PER-06</span>서버 협업 역량</a>\n  <a href=\"#personalfull-ch8\"><span class=\"code\">FS-PER-07</span>압박 질문 연결</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : CAREER-SYSTEM-PROJECT</span>\n    <span>SCOPE : SYSTEM DESIGN · PROJECT · FULLSTACK POSITIONING</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>시스템 설계와 프로젝트 심층 면접</h1>\n  <p class=\"hero-sub\">시스템 설계 면접, 프로젝트 심층 면접, 풀스택 개발자 대응을 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED INTERVIEW PATH · SOURCES : 3 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>학습 로드맵</h2></div>\n<p class=\"lede\">이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다.</p>\n<ul><li>시스템 설계 면접</li><li>프로젝트 심층 면접</li><li>풀스택 개발자 대응</li></ul>\n</section>\n\n<section id=\"career-readiness-gate\">\n<div class=\"ch-head\"><span class=\"ch-code\">GATE</span><h2>CAREER READINESS GATE</h2></div>\n<p class=\"lede\"><strong>시스템 설계·프로젝트 답변 게이트</strong>는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">시스템 설계·프로젝트 답변 게이트</span>\n시스템 설계와 프로젝트 경험을 요구사항, 제약, 선택지, trade-off, 검증 증거로 연결한다.\n</div>\n<table>\n<tr><th>준비 결과</th><th>면접에서 보여야 하는 신호</th><th>미달 신호</th></tr>\n<tr><td>30초 결론</td><td>첫 문장에서 판단 기준과 결론이 나온다.</td><td>배경 설명이 길고 질문의 핵심을 늦게 잡는다.</td></tr>\n<tr><td>90초 확장</td><td>대안, trade-off, 실패 모드, 검증 증거가 이어진다.</td><td>장점만 말하고 깨지는 조건을 말하지 못한다.</td></tr>\n<tr><td>압박 꼬리질문</td><td>모르는 범위와 직접 경험 범위를 분리한 뒤 확인 방법을 말한다.</td><td>직접 하지 않은 일을 경험처럼 포장한다.</td></tr>\n</table>\n<ul><li>설계 질문에서 actor, data, API, state, async job, observability, rollback을 순서대로 닫는다.</li><li>프로젝트 답변에서 개인 기여, 팀 기여, 외부 제약, 버린 대안을 분리한다.</li><li>성과를 기능 목록이 아니라 전후 지표, QA 감소, 장애 예방, 사용자 작업 시간 변화로 설명한다.</li></ul>\n</section>\n\n<section id=\"career-answer-rubric\">\n<div class=\"ch-head\"><span class=\"ch-code\">RUBRIC</span><h2>ANSWER QUALITY RUBRIC</h2></div>\n<p class=\"lede\">답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다.</p>\n<table>\n<tr><th>등급</th><th>답변 상태</th><th>보정 기준</th></tr>\n<tr><td>S</td><td>결론, 기준, trade-off, 실패 모드, 검증 증거, 본인 기여가 모두 분리된다.</td><td>압박 질문 2개를 붙여도 같은 경계와 증거를 유지한다.</td></tr>\n<tr><td>A</td><td>핵심 개념과 실무 예시는 좋지만 수치나 산출물 증거가 일부 비어 있다.</td><td>PR·ADR·지표·장애기록·QA ticket 중 최소 2개를 붙인다.</td></tr>\n<tr><td>B</td><td>개념 설명은 가능하지만 경험, 대안, 실패 조건이 약하다.</td><td>직접 경험, 일부 참여, 설계 지식을 문장 안에서 분리한다.</td></tr>\n<tr><td>C</td><td>기술명과 기능 목록 중심이고 면접관이 기여도와 판단 기준을 확인하기 어렵다.</td><td>질문을 다시 정의하고 30초 결론부터 재작성한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-pressure-loop\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOOP</span><h2>PRESSURE RESPONSE LOOP</h2></div>\n<p class=\"lede\">압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">PRESSURE RESPONSE LOOP</span>\n1. 질문을 한 문장으로 재정의한다<br>\n2. 직접 경험 / 일부 경험 / 설계 지식을 분리한다<br>\n3. 판단 기준 2개만 말한다<br>\n4. 증거 하나와 실패 모드 하나를 붙인다<br>\n5. 남은 불확실성은 검증 계획으로 닫는다\n</div>\n<table>\n<tr><th>압박 질문</th><th>복구 답변</th><th>피해야 할 방향</th></tr>\n<tr><td>그 프로젝트에서 본인이 실제로 결정한 것은 무엇인가요?</td><td>결정 소유 범위, 제약, 대안, 선택 이유, 결과 증거를 한 문장씩 끊어 답한다.</td><td>질문을 피하려고 일반론을 길게 늘리는 것</td></tr>\n<tr><td>그건 본인이 한 일인가요?</td><td>본인 결정, 팀 결정, 외부 제약을 분리하고 본인이 소유한 판단만 말한다.</td><td>팀 성과 전체를 개인 성과처럼 말하는 것</td></tr>\n<tr><td>수치나 증거가 없으면 어떻게 확인하나요?</td><td>정량 지표가 없었던 한계를 인정하고, 재현 절차·QA ticket·before/after·PR diff 같은 대체 증거를 제시한다.</td><td>좋아졌다고만 말하는 것</td></tr>\n</table>\n</section>\n\n<section id=\"career-evidence-packet\">\n<div class=\"ch-head\"><span class=\"ch-code\">EVIDENCE</span><h2>EVIDENCE PACKET</h2></div>\n<p class=\"lede\">면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다.</p>\n<table>\n<tr><th>증거 묶음</th><th>준비할 항목</th><th>면접에서 쓰는 방식</th></tr>\n<tr><td>핵심 산출물</td><td>architecture sketch, project depth ledger, before/after metric, PR·ADR·지표·장애기록·QA ticket</td><td>주장 뒤에 바로 붙일 수 있는 근거로 정리한다.</td></tr>\n<tr><td>공통 증거</td><td>PR·ADR·지표·장애기록·QA ticket</td><td>기술 판단, 협업 합의, 결과 확인을 한 번에 보여준다.</td></tr>\n<tr><td>답변 카드</td><td>질문, 30초 결론, 90초 확장, 압박 꼬리질문, 위험 표현, 대체 문장</td><td>면접 전날 같은 질문을 다시 말하며 품질을 점검한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-output-packet\">\n<div class=\"ch-head\"><span class=\"ch-code\">OUTPUT</span><h2>CAREER OUTPUT PACKET</h2></div>\n<p class=\"lede\">A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다.</p>\n<pre class=\"snippet-card\"><code>career_output_packet:\n  document: career-system-project\n  target_gate: \"시스템 설계·프로젝트 답변 게이트\"\n  before_answer: \"도구명, 역할명, 감상 중심으로 말해 기여 범위와 결과가 흐릿한 답변\"\n  after_answer: \"질문 재정의 → 본인 결정 범위 → 판단 기준 → 버린 대안 → 전후 증거 → 남은 리스크 순서의 답변\"\n  evidence_to_attach:\n    - architecture sketch\n    - project depth ledger\n    - PR/ADR/metric/incident record/QA ticket\n    - reviewer_follow_up_answer\n  interview_use: \"30초 결론은 after_answer의 첫 두 줄로 말하고, 90초 확장은 evidence_to_attach와 pressure response로 확장한다\"</code></pre>\n<table>\n<tr><th>Before</th><th>After</th><th>검증 질문</th></tr>\n<tr><td>“시스템 설계와 프로젝트 경험을 요구사항, 제약, 선택지, trade-off, 검증 증거로 연결한다.”를 감상처럼 길게 설명한다.</td><td>설계 질문에서 actor, data, API, state, async job, observability, rollback을 순서대로 닫는다.</td><td>본인 결정, 수치, 산출물, 실패 조건이 한 문장 안에 보이는가?</td></tr>\n<tr><td>“팀에서 처리했습니다”처럼 소유권이 흐릿하다.</td><td>결정 소유 범위, 제약, 대안, 선택 이유, 결과 증거를 한 문장씩 끊어 답한다.</td><td>직접 경험과 설계 지식의 경계가 분리되어 있는가?</td></tr>\n</table>\n</section>\n\n<section id=\"career-final-drill\">\n<div class=\"ch-head\"><span class=\"ch-code\">DRILL</span><h2>FINAL 10 MINUTE DRILL</h2></div>\n<p class=\"lede\">면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다.</p>\n<table>\n<tr><th>시간</th><th>할 일</th><th>완료 기준</th></tr>\n<tr><td>0-3분</td><td>시스템 설계·프로젝트 답변 게이트 질문 하나를 30초 결론으로 말한다.</td><td>첫 문장에 결론과 판단 기준이 있다.</td></tr>\n<tr><td>3-6분</td><td>같은 질문을 90초 확장으로 말한다.</td><td>대안, trade-off, 실패 모드, 증거가 포함된다.</td></tr>\n<tr><td>6-8분</td><td>압박 꼬리질문 하나를 붙여 답변을 복구한다.</td><td>모르는 범위를 숨기지 않고 확인 방법으로 닫는다.</td></tr>\n<tr><td>8-10분</td><td>DANGEROUS PHRASES를 제거하고 대체 문장으로 바꾼다.</td><td>추상 표현 없이 본인 기여와 증거가 남는다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">DANGEROUS PHRASES</span>\n<p>“많이 해봤습니다”, “대충 알고 있습니다”, “그냥 최적화했습니다”, “팀에서 처리했습니다”처럼 범위와 증거가 없는 표현은 약하게 들립니다. “제가 소유한 결정은 A이고, B 제약 때문에 C를 선택했으며, 결과는 D 증거로 확인했습니다”로 바꿉니다.</p>\n</div>\n</section>\n\n<section id=\"doc-system\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>시스템 설계 면접</h2></div>\n</section>\n\n<section id=\"system-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-00</span><h2>공통 답변 흐름</h2></div>\n<div class=\"serial-card\"><span class=\"sc-label\">SYSTEM DESIGN FRAME</span>1. 사용자와 목표 확인<br>2. 기능 요구사항과 비기능 요구사항 분리<br>3. 데이터 규모, 권한, 실시간성, 정확도 질문<br>4. 핵심 데이터 모델과 API 계약 정의<br>5. 프론트 상태와 백엔드/DB 책임 분리<br>6. 성능, 보안, 접근성, 관측성 기준 추가<br>7. 대안과 포기한 것을 명시</div>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>요구사항을 묻기 전에 기술 스택부터 말하면 약합니다. 면접관은 정답 구조보다 사고 순서를 봅니다.</p></div>\n</section>\n\n<section id=\"system-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-01</span><h2>Q. 관리자 대시보드를 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>관리자 대시보드는 단순 목록 화면이 아니라 검색, 필터, 권한, 감사 로그, 대량 데이터, 실패 상태, 운영 액션을 포함한 업무 도구입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>관리자 대시보드는 사용자가 많지 않아도 한 번의 오조작 영향이 큰 시스템입니다. 검색과 목록뿐 아니라 권한, audit log, bulk action, dry-run, 실패 복구가 설계 대상입니다. 면접에서는 UI 배치보다 actor, resource, action, evidence가 어떻게 남는지 말해야 깊이가 납니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 사용자 역할, 데이터 규모, 검색/필터 요구, 권한별 action, 실시간성 필요 여부를 확인합니다. 이후 URL state 기반 필터, cursor 또는 page pagination, 서버 filtering/sorting, 권한별 action guard, audit log, loading/empty/error 상태를 설계합니다.</div>\n<h3>90초 답변</h3><p>데이터 모델은 user/admin role, resource, action, audit event를 분리합니다. API는 목록 조회, 상세 조회, 상태 변경, bulk action을 나누고, 목록 API는 pagination과 filter contract를 명확히 합니다. 프론트는 URL state로 검색 조건을 공유 가능하게 하고, 서버 상태와 선택/편집 UI 상태를 분리합니다. 운영 관점에서는 action 실패, 권한 거부, 중복 클릭, 부분 성공을 처리해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>대량 데이터는?</td><td>서버 pagination/filtering, virtualization, export job 분리를 고려합니다.</td></tr><tr><td>권한은?</td><td>프론트는 UX guard, 서버는 최종 인가와 audit log를 담당합니다.</td></tr><tr><td>관측성은?</td><td>action 실패율, latency, audit event, traceId를 남깁니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>차트와 카드 배치만 말하면 디자인 답변이 됩니다. 데이터 계약과 운영 액션을 함께 말하세요.</p></div>\n</section>\n\n<section id=\"system-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-02</span><h2>Q. 대형 Data Grid 입력 시스템을 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>대형 grid는 렌더링 문제와 데이터 정합성 문제가 동시에 있습니다. 화면 cell state와 저장 가능한 domain model을 분리해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>대형 Data Grid는 표가 아니라 수천 개의 작은 입력 폼과 검증 결과가 동시에 있는 시스템입니다. 원본 데이터, draft, dirty state, validation error, selection, focus가 섞이면 저장 취소와 실패 복구가 어려워집니다. 렌더링 최적화와 데이터 정합성 설계를 동시에 말해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">행 수, 컬럼 수, 편집 방식, 저장 단위, validation 위치를 먼저 확인합니다. grid는 virtualization으로 렌더링 비용을 줄이고, serverData와 draftData, validationErrors, dirtyRows를 분리해 저장 취소와 실패 복구가 가능하게 설계합니다.</div>\n<h3>90초 답변</h3><p>column definition은 표시 설정이 아니라 formatter, parser, editor, validator를 가진 입력 계약으로 봅니다. cell-level validation은 즉시 피드백을 주고, row-level validation은 cross-field 규칙을 확인하며, submit-level validation은 중복이나 서버 상태 의존 규칙을 처리합니다. 대량 저장은 전체 submit보다 changed rows 기반 patch나 batch job을 고려합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>모든 row를 React state에 두면?</td><td>렌더링과 메모리 비용이 커질 수 있어 변경분 중심 상태와 virtualization을 봅니다.</td></tr><tr><td>Excel 업로드는?</td><td>parse, mapping, preview, validation, save를 단계로 나눕니다.</td></tr><tr><td>저장 실패는?</td><td>row/cell 단위 오류를 매핑하고 성공/실패 partial result를 보여줍니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>Data Grid 라이브러리 이름만 말하지 말고 상태 구조와 validation 책임을 말해야 합니다.</p></div>\n</section>\n\n<section id=\"system-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-03</span><h2>Q. 실시간 대시보드를 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>실시간은 항상 WebSocket이 답이 아닙니다. 정확도, 지연 허용치, 업데이트 빈도, 사용자 수, reconnect 비용으로 polling, SSE, WebSocket을 고릅니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>실시간성은 지연 시간이 0이라는 뜻이 아니라 허용 가능한 freshness와 전달 방식의 선택입니다. polling은 단순하고 견고하지만 지연과 낭비가 있고, SSE는 단방향 stream에 적합하며, WebSocket은 양방향 상호작용에 강하지만 연결 운영 비용이 큽니다. 연결 상태와 데이터 stale 상태를 UI가 설명해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 어느 정도 지연을 허용하는지, 양방향 통신이 필요한지, 데이터 손실이 치명적인지 확인합니다. 단방향 알림이나 지표는 SSE, 낮은 빈도 갱신은 polling, 양방향 협업이나 즉시성이 강한 기능은 WebSocket을 검토합니다.</div>\n<h3>90초 답변</h3><p>프론트는 connection state, stale state, reconnect, backoff, 마지막 업데이트 시각을 보여줘야 합니다. 백엔드는 fan-out, rate limit, backpressure, message ordering을 고려합니다. 지표 대시보드는 데이터가 늦을 수 있음을 사용자에게 표시하고, 알림은 중복과 누락을 막기 위해 event id나 cursor를 둘 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>polling 단점은?</td><td>불필요한 요청과 지연이 생기지만 단순하고 운영이 쉽습니다.</td></tr><tr><td>WebSocket 단점은?</td><td>연결 관리, scale-out, 인증 갱신, reconnect가 복잡합니다.</td></tr><tr><td>데이터가 stale하면?</td><td>마지막 업데이트 시각과 동기화 상태를 명확히 보여줍니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“실시간이니까 WebSocket”이라고 바로 답하지 마세요. 요구사항을 먼저 나눠야 합니다.</p></div>\n</section>\n\n<section id=\"system-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-04</span><h2>Q. 복잡한 multi-step form을 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>복잡한 form은 입력 필드 묶음이 아니라 상태 전이와 validation, 임시 저장, 권한, 서버 검증이 결합된 workflow입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>multi-step form은 field collection이 아니라 상태 전이 모델입니다. 단계별 입력 가능 조건, 임시 저장, 뒤로가기, 서버 검증 실패, 권한 변경이 모두 사용자 흐름을 바꿉니다. state machine까지 쓰지 않더라도 가능한 상태와 전이를 명확히 두면 예외 처리가 안정됩니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">단계 의존성, 임시 저장, 뒤로 가기, validation 범위, 제출 후 수정 가능 여부를 먼저 확인합니다. 상태는 step state, draft data, validation errors, server snapshot으로 나누고, schema validation과 서버 validation을 모두 고려합니다.</div>\n<h3>90초 답변</h3><p>각 step이 독립인지, 이전 입력이 다음 step 계산에 영향을 주는지에 따라 state machine을 검토할 수 있습니다. 사용자가 이탈해도 draft를 복구해야 하면 local persistence나 서버 draft 저장이 필요합니다. validation은 field, section, submit 단계로 나누고 서버 오류는 사용자가 수정할 수 있는 위치에 매핑해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>dirty check는?</td><td>server snapshot과 draft를 비교하거나 dirty field/row를 추적합니다.</td></tr><tr><td>임시 저장은?</td><td>저장 주기, 충돌, 만료, 복구 UX를 함께 설계합니다.</td></tr><tr><td>권한이 step별로 다르면?</td><td>서버 권한과 UI action visibility를 분리합니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>폼 라이브러리 이름보다 상태 전이와 실패 복구를 먼저 말하세요.</p></div>\n</section>\n\n<section id=\"system-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-05</span><h2>Q. 인증 기반 앱을 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>인증 기반 앱은 로그인 화면만이 아니라 session lifecycle, token refresh, 권한별 route/action, 만료 UX, 보안 정책을 포함합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>인증 기반 앱의 핵심은 로그인 성공 화면이 아니라 session lifecycle입니다. access token 만료, refresh 실패, 401/403 구분, 권한별 action, 로그아웃, 탭 간 동기화가 모두 사용자 경험과 보안에 영향을 줍니다. client guard와 server authorization의 역할을 분리해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">로그인, 세션 유지, 토큰 갱신, 로그아웃, 권한별 route/action 보호, 만료 시 복구 흐름을 설계합니다. 프론트는 사용자 경험과 route guard를 담당하고, 서버는 인증과 인가를 최종 검증합니다.</div>\n<h3>90초 답변</h3><p>JWT를 쓸지 session cookie를 쓸지는 보안, revoke, scale, 운영 복잡도를 기준으로 판단합니다. access token은 짧게, refresh token은 rotation과 탈취 감지를 고려할 수 있습니다. 권한은 route뿐 아니라 API action마다 확인해야 하고, 401과 403을 UI에서 다르게 처리해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>401과 403 차이는?</td><td>401은 인증 필요/만료, 403은 인증됐지만 권한 부족입니다.</td></tr><tr><td>토큰 갱신 실패는?</td><td>요청 큐 정리, 로그인 이동, unsaved draft 보호를 봅니다.</td></tr><tr><td>CSRF는?</td><td>cookie 기반 인증이면 SameSite, CSRF token, origin 검증을 고려합니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>프론트 route guard를 보안의 전부로 말하면 위험합니다. 서버 최종 검증을 반드시 말하세요.</p></div>\n</section>\n\n<section id=\"system-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-06</span><h2>Q. Excel 업로드와 validation 시스템을 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>Excel 업로드는 파일 처리 기능이 아니라 외부 비정형 입력을 도메인 데이터로 안전하게 변환하는 workflow입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Excel 업로드는 신뢰할 수 없는 외부 입력을 도메인 데이터로 변환하는 pipeline입니다. raw file, parsed row, normalized row, validation result를 나누면 오류 위치와 복구 흐름이 명확해집니다. 대용량이면 synchronous request가 아니라 job, progress, partial failure 모델이 필요합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 파일 크기, row 수, template version, validation 범위, 저장 단위를 확인합니다. 업로드는 parse, header mapping, preview, validation, error correction, submit 단계로 나누고, 오류는 row/cell 단위로 사용자가 수정할 수 있게 보여줍니다.</div>\n<h3>90초 답변</h3><p>데이터 모델은 raw file, parsed row, normalized domain row, validation result를 분리합니다. API는 upload session 생성, parse result 조회, validation 실행, 저장 요청으로 나눌 수 있습니다. 대용량은 synchronous request로 처리하지 말고 job과 progress를 둡니다. 보안상 파일 타입, 크기, formula injection, 개인정보 로그 노출도 봐야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>template 변경은?</td><td>template version과 column mapping을 관리합니다.</td></tr><tr><td>부분 성공은?</td><td>성공 row와 실패 row를 분리하고 재시도 경로를 둡니다.</td></tr><tr><td>대용량은?</td><td>비동기 job, progress, chunk 처리, timeout 정책을 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>row/cell 오류 매핑 화면, validation report, parse 실패 유형, 저장 job 상태 모델을 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>파일을 읽어서 저장한다고만 말하면 입력 신뢰성과 오류 복구 설계가 빠집니다.</p></div>\n</section>\n\n<section id=\"system-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-07</span><h2>Q. 무한 스크롤 피드를 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>무한 스크롤은 pagination UX가 아니라 정렬 안정성, cursor, 중복 제거, 캐시, 접근성, SEO를 함께 보는 설계 문제입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>무한 스크롤은 더 불러오기 UI가 아니라 정렬 안정성 문제입니다. offset은 중간 삽입으로 중복과 누락이 생길 수 있고, cursor는 특정 정렬 기준을 계약으로 삼습니다. 뒤로가기 복원, 접근성, SEO 필요 여부에 따라 무한 스크롤이 오히려 나쁜 선택일 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 정렬 기준, 새 글 삽입 방식, 뒤로가기 복원, SEO 필요 여부를 확인합니다. offset보다 cursor pagination을 우선 검토하고, client에서는 page cache, dedupe, loading/error/retry, scroll restoration을 설계합니다.</div>\n<h3>90초 답변</h3><p>시간순 피드는 중간에 새 데이터가 들어오면 offset이 밀려 중복이나 누락이 생길 수 있습니다. cursor는 createdAt+id 같은 안정적인 기준을 씁니다. 접근성 측면에서는 keyboard 이동, footer 도달성, “더 보기” 대체 버튼을 고려합니다. 검색 노출이 중요한 콘텐츠는 SSR/SSG와 페이지형 pagination이 더 적합할 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>중복 제거는?</td><td>id 기반 dedupe와 cursor 안정성을 같이 봅니다.</td></tr><tr><td>뒤로가기 복원은?</td><td>scroll position과 page cache를 보존합니다.</td></tr><tr><td>실시간 새 글은?</td><td>상단 새 글 알림으로 사용자 선택을 유도합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>cursor contract, scroll restoration 테스트, dedupe 로직, 접근성 대체 흐름을 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>IntersectionObserver만 말하면 데이터 정합성과 UX 복원 문제가 빠집니다.</p></div>\n</section>\n\n<section id=\"system-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-08</span><h2>Q. 운영 장애 복구용 admin tool을 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>운영 도구는 강력한 권한을 가진 위험한 UI이므로 권한, 감사 로그, dry-run, 승인, rollback 가능성이 핵심입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>운영 복구 도구는 일반 사용자 기능보다 더 강한 권한과 더 큰 피해 반경을 가집니다. 그래서 execute API보다 preview/dry-run, approval, audit, idempotency, rollback 가능성 설계가 먼저입니다. 잘못 누른 한 번의 action이 데이터 손상으로 이어지지 않도록 방어선을 여러 겹 둡니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 어떤 장애를 복구하는 도구인지, 누가 실행할 수 있는지, 잘못 실행했을 때 피해가 무엇인지 묻습니다. 모든 action은 권한, 입력 검증, dry-run, confirmation, audit log, rate limit, rollback 절차를 포함해야 합니다.</div>\n<h3>90초 답변</h3><p>데이터 모델은 operation, target, actor, approval, result, audit event를 분리합니다. API는 preview/dry-run과 execute를 나누고 idempotency key를 둡니다. 프론트는 영향 범위, 변경 전후, 위험도, 실행 결과를 명확히 보여줘야 합니다. 관측성은 action success/failure와 traceId를 남깁니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>실수 방지는?</td><td>dry-run, confirmation, approval, 제한된 권한으로 막습니다.</td></tr><tr><td>감사 로그는?</td><td>actor, target, action, before/after, result를 남깁니다.</td></tr><tr><td>rollback은?</td><td>undo 가능 여부를 action별로 분류하고 runbook을 둡니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>audit log schema, dry-run 결과 화면, 권한 matrix, 장애 runbook을 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>운영 도구는 편의성보다 오조작 방지와 추적성이 우선입니다.</p></div>\n</section>\n\n<section id=\"system-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-09</span><h2>Q. 글로벌 다국어 서비스를 설계해보세요.</h2></div>\n<h3>핵심 개념</h3><p>다국어 서비스는 문자열 치환만이 아니라 locale, timezone, currency, number format, fallback, 번역 workflow를 포함합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>다국어 서비스는 문자열 치환이 아니라 locale-aware product입니다. 날짜, 숫자, 통화, 정렬, plural, timezone, URL, SEO, 번역 QA가 모두 포함됩니다. SSR이 있다면 서버와 클라이언트의 locale 입력이 달라 hydration mismatch가 생기지 않게 해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 지원 locale, 기본 언어, fallback, SEO, 동적 콘텐츠 번역 여부를 확인합니다. 프론트는 i18n key와 namespace, lazy loading, date/number format을 관리하고, 백엔드는 사용자 locale과 콘텐츠 locale을 명확히 저장합니다.</div>\n<h3>90초 답변</h3><p>SSR이 있는 서비스는 서버와 클라이언트 locale이 달라 hydration mismatch가 생기지 않게 해야 합니다. 번역 key는 제품 영역별로 관리하고 미번역 fallback과 QA workflow를 둡니다. 검색/SEO가 중요하면 locale별 URL, hreflang, canonical을 설계해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>key 관리 기준은?</td><td>도메인 namespace와 재사용 기준을 정합니다.</td></tr><tr><td>시간대는?</td><td>저장은 UTC, 표시는 사용자 timezone 기준으로 합니다.</td></tr><tr><td>번역 누락은?</td><td>fallback, CI check, QA 리포트로 관리합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>i18n key 구조, locale routing, missing key 리포트, 날짜/통화 테스트 케이스를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>다국어를 텍스트 파일 교체로만 보면 날짜, 숫자, SEO, QA 비용을 놓칩니다.</p></div>\n</section>\n\n<section id=\"system-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-10</span><h2>화이트보드 진행 순서</h2></div>\n<p class=\"lede\">시스템 설계 면접은 바로 컴포넌트를 그리는 시험이 아닙니다. 면접관 신호를 보면서 요구사항을 좁히고, 비기능 요구사항과 운영 리스크를 구조화하는 과정입니다.</p>\n<table>\n<tr><th>순서</th><th>말할 내용</th><th>면접관 신호</th></tr>\n<tr><td>1. 요구사항 정리</td><td>사용자, 핵심 시나리오, 제외 범위, 성공 기준을 질문한다</td><td>“그 부분은 가정해도 됩니다”라고 하면 다음 단계로 이동</td></tr>\n<tr><td>2. 비기능 요구사항</td><td>트래픽, 지연, 정합성, 보안, 접근성, 운영 권한을 확인한다</td><td>성능이나 장애를 물으면 운영 관점으로 확장</td></tr>\n<tr><td>3. 데이터 모델</td><td>핵심 entity, 상태 전이, 소유권, 감사 로그 필요성을 정리한다</td><td>DB나 API 질문이 나오면 계약과 제약 조건을 구체화</td></tr>\n<tr><td>4. API와 화면 흐름</td><td>읽기/쓰기 API, pagination, validation, error recovery를 연결한다</td><td>프론트 중심 질문이면 상태 구조와 UX 복구를 깊게 설명</td></tr>\n<tr><td>5. 병목과 장애 대응</td><td>캐시, 큐, retry, idempotency, rollback, observability를 붙인다</td><td>scale 질문이 나오면 병목 하나를 골라 trade-off를 말한다</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">답변 흐름</span>\n요구사항 정리 → 비기능 요구사항 → 데이터 모델 → API와 화면 흐름 → 병목과 장애 대응 → 검증 계획 순서로 말합니다.<br>\n화이트보드에는 모든 것을 그리지 말고, 선택 기준이 드러나는 경계와 데이터 흐름만 남깁니다.\n</div>\n</section>\n\n<section id=\"system-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-11</span><h2>Capacity estimation</h2></div>\n<p class=\"lede\">시스템 설계에서 Capacity estimation은 정확한 숫자 맞히기가 아니라, 어떤 가정으로 병목을 추정하고 어떤 지점부터 구조가 달라지는지 말하는 훈련입니다.</p>\n<table>\n<tr><th>항목</th><th>질문</th><th>답변 포인트</th></tr>\n<tr><td>QPS</td><td>평균과 peak traffic은 얼마인가</td><td>DAU, 사용자당 요청 수, peak factor로 대략 산정합니다.</td></tr>\n<tr><td>read/write ratio</td><td>읽기와 쓰기 비율은 어떻게 다른가</td><td>읽기가 많으면 cache/replica, 쓰기가 많으면 partition/queue/lock을 봅니다.</td></tr>\n<tr><td>storage size</td><td>하루 데이터 증가량은 얼마인가</td><td>row 크기 × 생성량 × 보관 기간으로 추정하고 index 크기도 고려합니다.</td></tr>\n<tr><td>latency budget</td><td>사용자가 허용할 응답 시간은 얼마인가</td><td>frontend, gateway, app, DB, external API 예산으로 나눕니다.</td></tr>\n<tr><td>DB connection pool</td><td>동시 요청을 DB가 감당할 수 있는가</td><td>요청 시간, 쿼리 시간, pool 대기, transaction 길이를 함께 봅니다.</td></tr>\n<tr><td>queue worker 수</td><td>비동기 작업이 밀리지 않는가</td><td>생산 속도, 처리 시간, queue lag 목표로 worker 수를 계산합니다.</td></tr>\n<tr><td>고가용성·DR</td><td>장애가 났을 때 얼마나 빨리 복구해야 하는가</td><td>SPOF를 제거하고 RPO/RTO, active-active 필요성, failover 절차를 정합니다.</td></tr>\n<tr><td>load shedding</td><td>과부하 때 무엇을 포기할 수 있는가</td><td>비핵심 요청 차단, degraded mode, queue backpressure로 핵심 흐름을 보호합니다.</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">간단 산정 예시</span>\nDAU 100,000명 × 사용자당 20 요청 = 2,000,000 requests/day<br>\n평균 QPS ≈ 2,000,000 / 86,400 = 23 QPS, peak factor 10이면 약 230 QPS<br>\n쓰기 비율이 10%라면 peak write는 약 23 QPS입니다. 이 정도는 단일 DB와 cache로 충분할 수 있지만, query가 느리거나 transaction이 길면 connection pool이 먼저 병목이 됩니다.\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">HA/DR 답변</span>\n고가용성·DR 질문에서는 먼저 SPOF를 찾고, RPO/RTO 목표를 정한 뒤 active-active가 필요한지 판단합니다. 모든 요청을 지키려 하기보다 load shedding으로 핵심 사용자 흐름을 보호할 수 있는지도 함께 말합니다.\n</div>\n</section>\n\n<section id=\"system-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-12</span><h2>고가용성·DR</h2></div>\n<p class=\"lede\">고가용성·DR 질문은 “서버를 여러 대 둔다”보다 어떤 실패를 가정하고, 어느 수준의 중단과 데이터 손실을 허용하는지 설명하는 문제입니다. 먼저 SPOF를 찾고 RPO/RTO를 숫자로 합의한 뒤 구조를 선택합니다.</p>\n<table>\n<tr><th>주제</th><th>면접에서 말할 기준</th><th>주의점</th></tr>\n<tr><td>SPOF 제거</td><td>load balancer, app instance, DB primary, cache, queue, DNS, external API 중 단일 장애 지점을 찾습니다.</td><td>컴퓨트만 이중화하고 DB, 배포, 운영 권한을 빼면 답변이 얕아집니다.</td></tr>\n<tr><td>active-passive</td><td>평상시 한쪽이 처리하고 장애 시 failover합니다. 운영이 단순하고 비용이 낮지만 전환 시간이 있습니다.</td><td>자동 failover 기준과 split-brain 방지를 설명해야 합니다.</td></tr>\n<tr><td>active-active</td><td>여러 region 또는 zone이 동시에 트래픽을 처리합니다. 가용성은 높지만 데이터 정합성, routing, 비용이 복잡합니다.</td><td>쓰기 충돌, session affinity, global rate limit을 함께 봅니다.</td></tr>\n<tr><td>RPO/RTO</td><td>RPO는 허용 가능한 데이터 손실 시간, RTO는 복구까지 허용 가능한 시간입니다.</td><td>“장애가 나면 복구합니다”가 아니라 수치 기준을 먼저 말해야 합니다.</td></tr>\n<tr><td>backup vs replication</td><td>replication은 빠른 전환에 유리하고 backup은 논리적 삭제·오염 복구에 필요합니다.</td><td>replication만 있으면 잘못 삭제된 데이터도 빠르게 복제됩니다.</td></tr>\n<tr><td>부하 방어</td><td>rate limit, backpressure, graceful degradation, load shedding으로 핵심 기능을 보호합니다.</td><td>모든 요청을 끝까지 처리하려 하면 장애가 연쇄적으로 커집니다.</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">30초 답변</span>\n고가용성 설계에서는 먼저 SPOF를 찾고, 서비스가 허용하는 RPO/RTO를 정합니다. 그 기준에 따라 multi-AZ active-passive, multi-region active-active, backup/restore, replication, failover를 선택합니다. 장애 중에는 graceful degradation, rate limit, backpressure, load shedding으로 핵심 경로를 보호합니다.\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">90초 답변</span>\n예를 들어 B2B admin 서비스라면 결제 승인처럼 즉시성이 큰 기능과 리포트 다운로드처럼 지연 가능한 기능을 나눕니다. 앱 서버는 multi-AZ로 수평 확장하고, DB는 primary/replica와 automated backup을 둡니다. RTO가 짧아야 하면 failover 자동화와 health check를 강화하고, RPO가 거의 0이어야 하면 동기 복제나 쓰기 경로 제약을 검토합니다. 반대로 비용이 중요하면 일부 기능은 read-only mode나 degraded mode로 낮춰 운영할 수 있습니다.\n</div>\n<table>\n<tr><th>꼬리질문</th><th>답변 방향</th></tr>\n<tr><td>replication lag가 있으면?</td><td>read-after-write가 필요한 요청은 primary로 보내고, lag metric을 보고 replica routing을 제한합니다.</td></tr>\n<tr><td>DB primary 장애는?</td><td>failover, connection 재시도, idempotency, transaction 중단 복구, 운영 알림을 함께 설계합니다.</td></tr>\n<tr><td>외부 API 장애는?</td><td>timeout, circuit breaker, fallback, queueing, 사용자 고지, 재처리 runbook을 둡니다.</td></tr>\n<tr><td>장애 훈련은?</td><td>backup restore drill, failover rehearsal, runbook review, alert threshold 검증을 정기적으로 합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"system-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-13</span><h2>설계 리뷰 게이트</h2></div>\n<p class=\"lede\">시스템 설계 면접에서 좋은 답변은 그림을 많이 그리는 답변이 아니라, 빠뜨리면 장애가 되는 결정을 순서대로 닫아 가는 답변입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SYSTEM DESIGN REVIEW GATE</span>\n요구사항과 비기능 요구를 분리하고, API 계약, 데이터 모델, 읽기/쓰기 경로, capacity, consistency, failure mode, observability, rollout 순서로 검토합니다. 각 단계마다 “이 선택이 깨지는 조건”과 “깨졌는지 볼 지표”를 붙이면 설계가 운영 가능한 수준으로 올라갑니다.\n</div>\n<table>\n<tr><th>게이트</th><th>확인 질문</th><th>좋은 답변의 증거</th></tr>\n<tr><td>요구사항</td><td>핵심 사용자 흐름과 제외 범위는 무엇인가?</td><td>MVP 범위, SLA/SLO, 데이터 보존 기간, 권한 범위를 명확히 합니다.</td></tr>\n<tr><td>API·계약</td><td>클라이언트와 서버가 무엇을 약속하는가?</td><td>pagination, idempotency, error code, backward compatibility를 말합니다.</td></tr>\n<tr><td>데이터 모델</td><td>정규화와 조회 성능의 균형은 어디인가?</td><td>entity, aggregate boundary, index, migration 전략을 연결합니다.</td></tr>\n<tr><td>확장성</td><td>읽기/쓰기 중 무엇이 먼저 병목이 되는가?</td><td>QPS, payload size, fan-out, cache hit ratio, DB write limit을 추정합니다.</td></tr>\n<tr><td>정합성</td><td>즉시 일관성이 꼭 필요한 경로는 무엇인가?</td><td>strong consistency와 eventual consistency를 사용자 영향으로 나눕니다.</td></tr>\n<tr><td>장애</td><td>어떤 dependency가 느리거나 죽으면 어떻게 되는가?</td><td>timeout, fallback, queue, degraded mode, manual recovery를 제시합니다.</td></tr>\n<tr><td>관측성</td><td>운영자가 무엇을 보고 판단하는가?</td><td>RED/USE metric, trace id, business metric, alert threshold를 말합니다.</td></tr>\n<tr><td>출시</td><td>한 번에 바꿀 수 없는 부분은 어떻게 전환하는가?</td><td>feature flag, dual-write/read, canary, rollback, data backfill을 말합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"system-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-14</span><h2>Trade-off Matrix</h2></div>\n<p class=\"lede\">면접관은 특정 기술을 골랐는지가 아니라, 왜 그 선택이 현재 제약에서 합리적인지 봅니다.</p>\n<table>\n<tr><th>선택지</th><th>유리한 경우</th><th>위험·비용</th><th>면접 답변 포인트</th></tr>\n<tr><td>동기 API vs Queue</td><td>즉시 결과가 필요하면 동기 API, 지연 허용·부하 흡수가 필요하면 queue</td><td>queue는 중복·순서·DLQ 운영이 필요합니다.</td><td>사용자 대기 가능 시간과 재처리 필요성을 기준으로 고릅니다.</td></tr>\n<tr><td>Cache vs DB 직조회</td><td>읽기 반복과 계산 비용이 크면 cache</td><td>stale data, invalidation, stampede가 생깁니다.</td><td>정합성 요구와 TTL, invalidation 주체를 함께 말합니다.</td></tr>\n<tr><td>SQL vs NoSQL</td><td>관계·transaction·ad-hoc query는 SQL, 대규모 key-value나 유연 스키마는 NoSQL</td><td>NoSQL은 쿼리 유연성과 transaction 경계가 제한될 수 있습니다.</td><td>데이터 접근 패턴이 먼저고 저장소 이름은 나중입니다.</td></tr>\n<tr><td>Monolith vs MSA</td><td>작은 팀과 빠른 일관성은 monolith, 독립 배포와 조직 분리가 필요하면 MSA</td><td>MSA는 네트워크, 관측성, 분산 트랜잭션 비용이 큽니다.</td><td>팀 구조와 운영 성숙도를 같이 봅니다.</td></tr>\n<tr><td>정규화 vs Denormalization</td><td>쓰기 정합성이 중요하면 정규화, 읽기 성능과 projection이 중요하면 denormalization</td><td>denormalization은 동기화와 재생성 비용이 있습니다.</td><td>source of truth와 projection 재생성 방법을 말합니다.</td></tr>\n<tr><td>Strong vs Eventual consistency</td><td>돈·권한·재고는 strong에 가깝게, 피드·검색·통계는 eventual 가능</td><td>강한 정합성은 latency와 가용성 비용이 있습니다.</td><td>업무 영향과 사용자 신뢰 기준으로 나눕니다.</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">TRADE-OFF MATRIX</span>\n설계 답변에서는 “A를 쓰겠습니다”보다 “A는 이 제약에서 좋지만 이런 실패 모드가 있어 B와 C로 보완합니다”가 전문적입니다. 선택의 단점까지 먼저 말하면 꼬리질문에서 방어가 쉬워집니다.\n</div>\n</section>\n\n<section id=\"system-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-15</span><h2>SYSTEM DESIGN PRESSURE DRILL</h2></div>\n<p class=\"lede\">압박 질문에서는 예쁜 아키텍처보다 숫자 가정, 병목 추정, 정합성 선택, 실패 대응, rollout/backfill/rollback 순서를 빠르게 닫는 능력을 봅니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">DAU→QPS→DB CONNECTION/CACHE/QUEUE/WORKER</span>\nDAU 500,000명 × 사용자당 30 요청 = 15,000,000 requests/day입니다. 평균 QPS는 약 174이고 peak factor 8이면 약 1,400 QPS입니다. DB에 직접 가는 비율이 30%이고 cache hit가 70%라면 peak DB read는 약 420 QPS입니다. 요청당 DB 점유 시간이 80ms이면 필요한 동시 connection은 대략 34개지만, transaction 지연과 p95를 고려해 pool wait metric을 봅니다. 비동기 작업이 초당 300개 생성되고 worker 1개가 초당 15개 처리하면 최소 20개 worker가 필요하며, queue lag 목표와 재시도율을 보고 여유를 둡니다.\n</div>\n<table>\n<tr><th>압박 질문</th><th>답변 방향</th><th>추가로 붙일 증거</th></tr>\n<tr><td>DAU만 주어졌을 때 QPS를 어떻게 계산하나요?</td><td>DAU, 사용자당 일 요청 수, 평균 QPS, peak factor, read/write ratio, payload 크기를 가정하고 병목 후보를 좁힙니다.</td><td>계산식과 가정 변경 시 구조가 바뀌는 임계점을 말합니다.</td></tr>\n<tr><td>DB connection이 먼저 터지면 어떻게 하나요?</td><td>pool wait, slow query, transaction 길이, N+1, cache hit, read replica, queue 분리를 순서대로 봅니다.</td><td>connection 수를 무작정 늘리면 DB가 더 불안정해질 수 있음을 말합니다.</td></tr>\n<tr><td>cache hit가 낮으면 무엇을 확인하나요?</td><td>key 설계, TTL, invalidation, user-specific cache, stampede, cacheable endpoint와 non-cacheable endpoint를 나눕니다.</td><td>hit ratio, stale 신고, origin QPS, p95 latency 전후를 봅니다.</td></tr>\n<tr><td>queue lag가 늘면 worker를 몇 개로 늘리나요?</td><td>producer rate, worker 처리율, retry율, poison message, downstream limit을 보고 필요한 worker 수와 backpressure를 계산합니다.</td><td>worker만 늘리면 외부 API quota나 DB write lock이 터질 수 있음을 설명합니다.</td></tr>\n<tr><td>consistency는 어디서 강하게 잡나요?</td><td>돈·권한·재고·중복 주문은 strong consistency 또는 idempotency/unique constraint를 우선하고, 피드·검색·통계는 eventual consistency를 허용합니다.</td><td>사용자에게 pending/synced/failed 상태를 어떻게 보여줄지 말합니다.</td></tr>\n<tr><td>failure mode는 무엇을 먼저 보나요?</td><td>DB failover, cache 장애, queue 적체, external API timeout, region/AZ 장애, 배포 실패를 dependency별로 나눕니다.</td><td>timeout, circuit breaker, degraded mode, runbook, alert를 붙입니다.</td></tr>\n<tr><td>rollout/backfill/rollback은 어떤 순서인가요?</td><td>expand schema, dual-write 또는 backward-compatible write, backfill, read switch, old path 제거 순서로 진행하고 feature flag와 canary로 blast radius를 줄입니다.</td><td>rollback은 코드, config, migration, data backfill의 되돌림 가능성을 분리합니다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">면접관 압박 질문</span>\n<p>“그 숫자는 어디서 나왔나요?”, “cache hit가 20%로 떨어지면?”, “DB connection이 100개 제한이면?”, “worker를 늘렸는데 lag가 그대로면?”, “backfill 중 구버전 앱이 쓰면?”, “rollback했는데 데이터는 이미 바뀌었으면?”에 답할 준비를 합니다.</p>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">30초 압축 답변</span>\n“먼저 DAU와 요청 수로 peak QPS를 잡고 read/write ratio, cache hit, DB connection, queue lag, worker 처리율로 병목을 좁힙니다. 그 다음 consistency가 필요한 경로와 eventual로 둘 경로를 나누고, dependency failure와 rollout/backfill/rollback 순서를 붙입니다. 숫자는 정답이 아니라 구조가 바뀌는 지점을 찾기 위한 가정입니다.”\n</div>\n</section>\n\n<section id=\"system-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-16</span><h2>시스템 설계 핵심 질문 20선</h2></div>\n<p class=\"lede\">시스템 설계 핵심 질문은 요구사항을 닫는 질문, 숫자를 세우는 질문, 실패를 가정하는 질문, 출시 순서를 검증하는 질문으로 나눠 준비합니다.</p>\n<table>\n<tr><th>축</th><th>구체 질문</th><th>답변 방향</th></tr>\n<tr><td>요구사항</td><td>사용자는 누구이고 가장 중요한 3개 user journey는 무엇인가요?</td><td>actor, primary flow, 제외 범위를 먼저 확정합니다.</td></tr>\n<tr><td>비기능</td><td>latency, availability, consistency 중 무엇이 가장 중요한가요?</td><td>SLO와 business critical path를 연결합니다.</td></tr>\n<tr><td>규모</td><td>DAU와 요청 수가 주어졌을 때 peak QPS는 얼마인가요?</td><td>평균 QPS, peak factor, read/write ratio를 계산합니다.</td></tr>\n<tr><td>데이터</td><td>source of truth와 projection은 무엇인가요?</td><td>정규화 모델과 조회 최적화 모델을 분리합니다.</td></tr>\n<tr><td>API</td><td>pagination, idempotency, error code 계약은 어떻게 잡나요?</td><td>클라이언트 복구 가능성과 서버 최종 검증을 함께 봅니다.</td></tr>\n<tr><td>DB</td><td>DB connection pool이 먼저 병목이면 어떤 선택지가 있나요?</td><td>slow query, transaction 길이, cache, replica, queue 분리를 봅니다.</td></tr>\n<tr><td>캐시</td><td>cache hit가 낮거나 stale data가 생기면 어떻게 대응하나요?</td><td>TTL, key 설계, invalidation, stampede 방어를 말합니다.</td></tr>\n<tr><td>큐</td><td>queue lag가 증가하면 worker 수를 어떻게 산정하나요?</td><td>producer rate, 처리율, retry율, downstream limit을 계산합니다.</td></tr>\n<tr><td>정합성</td><td>어떤 쓰기는 strong consistency가 필요하고 어떤 데이터는 eventual이어도 되나요?</td><td>돈·권한·재고와 피드·검색·통계를 구분합니다.</td></tr>\n<tr><td>장애</td><td>DB, cache, queue, external API 중 하나가 느려지면 사용자는 무엇을 보나요?</td><td>timeout, fallback, degraded mode, alert를 붙입니다.</td></tr>\n<tr><td>보안</td><td>인증과 인가는 어디서 검증하고 audit은 무엇을 남기나요?</td><td>client guard와 server authorization, actor/action/resource/result를 분리합니다.</td></tr>\n<tr><td>출시</td><td>대규모 schema 변경은 어떻게 rollout/backfill/rollback하나요?</td><td>expand-contract, feature flag, canary, backfill 검증을 말합니다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">압박 질문</span>\n<p>“지금 가정한 QPS가 10배면?”, “cache를 끄면 DB가 버티나요?”, “worker를 늘리면 downstream quota는요?”, “eventual consistency 중 사용자가 돈을 두 번 잃으면?”, “rollback했는데 backfill 데이터는 어떻게 되나요?”에 숫자와 실패 모드로 답합니다.</p>\n</div>\n</section>\n\n<section id=\"system-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-17</span><h2>시스템 설계 개념 인과관계</h2></div>\n<p class=\"lede\">시스템 설계 답변이 외운 티가 나는 이유는 기술 선택이 원인 없이 튀어나오기 때문입니다. 좋은 답변은 요구사항의 압력이 어떤 병목을 만들고, 그 병목 때문에 어떤 구조를 선택하며, 그 선택이 다시 어떤 비용을 만드는지 설명합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">SYSTEM DESIGN CAUSAL MODEL</span>사용자가 늘면 요청 수가 늘고, 요청 수가 늘면 DB connection, slow query, cache miss, queue lag 중 하나가 먼저 병목이 됩니다. 읽기 병목이면 cache, replica, projection을 검토하고, 쓰기 병목이면 transaction 길이, lock 범위, queue 분리, idempotency를 봅니다. 하지만 cache는 stale data를 만들고, queue는 중복 처리와 지연을 만들며, replica는 read-your-writes 문제를 만듭니다. 그래서 설계 답변은 “cache를 둔다”가 아니라 “읽기 반복이 많고 stale을 몇 초 허용할 수 있어서 cache를 두되 invalidation과 fallback을 이렇게 둔다”로 이어져야 합니다.</div>\n<table>\n<tr><th>원인</th><th>메커니즘</th><th>겉으로 보이는 현상</th><th>선택 기준</th></tr>\n<tr><td>읽기 요청이 쓰기보다 훨씬 많다</td><td>같은 데이터를 반복 조회해 DB와 network round trip이 누적된다</td><td>DB CPU, connection wait, p95 latency가 오른다</td><td>cache, read replica, materialized view를 쓰되 stale 허용 시간을 먼저 정한다</td></tr>\n<tr><td>쓰기 요청이 동시에 같은 row를 바꾼다</td><td>lock wait, lost update, deadlock 가능성이 커진다</td><td>timeout, retry 증가, transaction rollback이 보인다</td><td>optimistic lock, unique constraint, idempotency, queue 직렬화를 비교한다</td></tr>\n<tr><td>외부 API가 느리다</td><td>thread와 connection이 대기 상태로 묶인다</td><td>CPU는 낮은데 응답이 느리고 pool wait가 증가한다</td><td>timeout budget, circuit breaker, async job, degraded mode를 둔다</td></tr>\n<tr><td>데이터 마이그레이션이 크다</td><td>schema lock, backfill 부하, 구버전 코드와 신버전 코드 공존 문제가 생긴다</td><td>배포 중 오류, 쓰기 실패, rollback 불가 상태가 생긴다</td><td>expand-contract, dual-write/read, canary, backfill 검증 순서로 닫는다</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">면접 답변 전환</span>\n<p>“트래픽이 많으면 캐시를 씁니다”라고 말하지 말고 “읽기 반복이 많아 origin DB가 병목이 되고, 이 데이터는 30초 stale을 허용할 수 있으므로 cache-aside를 둡니다. 대신 권한과 결제 상태는 stale 허용치가 낮아 cache하지 않거나 짧은 TTL과 명시적 purge를 둡니다”처럼 인과관계와 예외를 함께 말합니다.</p>\n</div>\n</section>\n\n<section id=\"system-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-18</span><h2>완성형 시스템 설계 사례: 대용량 B2B 관리자 데이터 처리</h2></div>\n<p class=\"lede\">전문가 수준의 시스템 설계 답변은 여러 주제를 따로 말하지 않습니다. 하나의 문제를 두고 요구사항, 트래픽, 데이터 모델, API, DB, 캐시, 큐, 장애, 배포를 같은 인과관계 안에서 연결합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">EXPERT SYSTEM DESIGN CASE</span>예제 요구사항은 “B2B 고객사가 수십만 건의 거래 데이터를 업로드하고, 운영자가 검증 오류를 수정하며, 대시보드에서 필터·집계·다운로드를 수행하는 관리자 시스템”입니다. 이 문제는 단순 CRUD가 아닙니다. 업로드는 비정형 입력을 도메인 데이터로 바꾸는 pipeline이고, 검증은 row/cell 오류를 사용자에게 되돌려야 하며, 조회는 대량 데이터와 권한, audit, export job을 함께 다뤄야 합니다. 따라서 설계는 UI 화면이 아니라 데이터가 어떤 상태를 거쳐 신뢰 가능한 데이터가 되는지부터 시작합니다.</div>\n<h3>1. 요구사항을 닫는 순서</h3>\n<p>먼저 사용자와 성공 기준을 좁힙니다. 운영자는 파일을 업로드하고, 시스템은 template version을 확인하고, parsing 결과를 preview로 보여주고, validation error를 row/cell 단위로 표시하며, 사용자가 수정한 뒤 저장합니다. 비기능 요구는 더 중요합니다. 업로드 파일은 최대 몇 MB인지, row 수는 1만인지 100만인지, 검증이 즉시 끝나야 하는지, 일부 성공을 허용하는지, tenant별 데이터가 완전히 격리되어야 하는지, audit log가 법적 증거인지 확인합니다. 이 질문을 먼저 하지 않으면 이후 기술 선택은 근거 없는 나열이 됩니다.</p>\n<h3>2. 데이터 모델과 상태 전이</h3>\n<p>핵심 entity는 <code>upload_session</code>, <code>raw_file</code>, <code>parsed_row</code>, <code>validation_error</code>, <code>domain_record</code>, <code>audit_event</code>로 나눕니다. raw file은 원본 증거이고, parsed row는 아직 신뢰할 수 없는 중간 표현이며, domain record는 검증을 통과해 업무 규칙을 만족한 최종 데이터입니다. 이 구분이 없으면 “파일은 올라갔는데 저장은 실패한 상태”, “일부 row만 성공한 상태”, “검증 규칙이 바뀐 뒤 재검증해야 하는 상태”를 설명할 수 없습니다. 상태 전이는 <code>UPLOADED → PARSED → VALIDATED_WITH_ERRORS | VALIDATED → COMMITTED | FAILED</code>처럼 명시하고, 각 전이에 actor와 timestamp를 남깁니다.</p>\n<h3>3. 동기 API와 비동기 job의 경계</h3>\n<p>파일 업로드 요청에서 parsing과 validation을 끝내려 하면 request timeout, memory pressure, DB connection 점유가 발생합니다. 그래서 업로드 API는 session을 만들고 파일을 object storage에 저장한 뒤 job id를 반환합니다. parsing worker는 파일을 읽어 row 단위로 저장하고, validation worker는 rule engine 또는 validator set을 적용합니다. 사용자는 polling, SSE, WebSocket 중 요구사항에 맞는 방식으로 progress를 봅니다. 여기서 queue를 넣는 이유는 “비동기가 멋져서”가 아니라 사용자 요청 경로에서 긴 작업을 분리하고, 실패를 재시도·DLQ·운영자 확인이 가능한 상태로 바꾸기 위해서입니다.</p>\n<h3>4. Capacity estimation과 병목 추론</h3>\n<p>예를 들어 하루 1,000개 tenant가 각각 100,000 row 파일을 2개씩 올리면 하루 2억 row를 parsing해야 합니다. 평균으로 나누면 작아 보이지만 업무 시간 peak에 몰릴 수 있습니다. row당 validation이 3ms면 단일 worker는 초당 약 333 row를 처리하고, 100,000 row 파일 하나는 약 5분이 걸립니다. 100개 파일이 동시에 들어오면 worker 수, DB write throughput, object storage read bandwidth, validation rule CPU가 병목 후보가 됩니다. 이때 worker만 늘리면 DB write lock이나 connection pool이 먼저 터질 수 있으므로 queue lag, worker throughput, DB write latency, connection pool wait를 함께 봅니다.</p>\n<h3>5. 조회와 인덱스 설계</h3>\n<p>운영 목록 화면은 tenant, status, date range, error type, uploader 같은 조건으로 조회합니다. <code>(tenant_id, status, created_at)</code> 같은 복합 인덱스는 equality 조건과 range/order 조건 순서를 보고 설계합니다. 하지만 모든 필터 조합에 인덱스를 만들면 쓰기 비용과 저장 공간이 폭증합니다. 자주 쓰는 조회 경로는 execution plan으로 검증하고, export는 화면 조회 API와 분리해 background job으로 처리합니다. offset pagination은 뒤 페이지에서 비용이 커질 수 있으므로 운영 목록은 cursor 또는 keyset pagination을 검토합니다.</p>\n<h3>6. 정합성과 실패 복구</h3>\n<p>저장 단계에서 “검증된 row만 domain_record로 commit”하는 것은 transaction 경계를 신중히 잡아야 합니다. 파일 하나 전체를 하나의 transaction으로 묶으면 lock과 undo/WAL이 커지고 실패 시 복구가 어렵습니다. batch 단위 commit을 쓰면 부분 성공이 생기므로 session 상태와 failed batch를 추적해야 합니다. 같은 파일을 사용자가 두 번 제출할 수 있으므로 upload checksum, idempotency key, unique constraint를 둡니다. commit 후 알림이나 downstream 이벤트가 필요하면 DB 변경과 이벤트 발행 사이 간극을 줄이기 위해 outbox를 둡니다.</p>\n<h3>7. 보안과 권한</h3>\n<p>프론트에서 tenant id를 보내더라도 서버는 principal 기준으로 tenant scope를 재계산해야 합니다. 파일에는 formula injection, 개인정보, 악성 payload가 들어올 수 있으므로 파일 크기, MIME, 확장자, sheet 수, formula escape, virus scan 필요성을 검토합니다. 다운로드 URL은 presigned URL을 쓰더라도 TTL, scope, audit log가 필요합니다. 관리자 action은 actor, tenant, resource, action, before/after, result, trace id를 audit event로 남깁니다.</p>\n<h3>8. 배포와 마이그레이션</h3>\n<p>validation rule 저장 구조를 바꾸거나 upload 상태 enum을 추가할 때는 구버전 worker와 신버전 worker가 동시에 떠 있을 수 있습니다. 먼저 nullable column이나 새 테이블을 추가하고, 구버전이 읽어도 깨지지 않는 형태로 dual-write 또는 backward-compatible write를 적용합니다. backfill 후 read path를 전환하고, 지표가 안정되면 옛 필드를 제거합니다. rollback은 코드만 되돌리는 것이 아니라 이미 생성된 새 상태와 데이터가 구버전에서 어떻게 보이는지까지 정의해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">전문가 답변의 핵심</span>\n<p>이 사례에서 좋은 답변은 “S3, SQS, Redis, RDS를 씁니다”가 아닙니다. “파일 업로드는 긴 작업이므로 요청 경로에서 분리하고, row 상태를 분리해 오류 복구를 가능하게 하며, tenant 격리와 audit을 서버에서 보장하고, worker 확장은 DB write throughput과 queue lag를 함께 보며, schema 변경은 expand-contract로 배포합니다”처럼 제약에서 구조가 도출되는 답변입니다.</p>\n</div>\n</section>\n\n<section id=\"system-system-design-deep-answer-upgrade\" class=\"answer-card\" data-answer-model=\"definition mechanism tradeoff failure evidence defense\">\n<div class=\"ch-head\"><span class=\"ch-code\">SD-19</span><h2>DEEP ANSWER MODEL</h2></div>\n<p class=\"lede\">시스템 설계 답변은 컴포넌트 나열이 아니라 요구사항 압력이 capacity estimation, bottleneck, 데이터 모델, API 계약, rollout, rollback 전략을 어떻게 결정하는지 보여주는 과정입니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">CONCEPT DEPTH</span>정의 → 내부 동작 → trade-off → 실패 모드 → 검증 증거 → FOLLOW-UP DEFENSE 순서로 답합니다. “캐시를 둔다”가 아니라 read/write ratio, freshness, 권한 데이터 여부, invalidation 비용, stale 허용 시간을 근거로 선택합니다.</div>\n<table>\n<tr><th>질문</th><th>부실한 답변</th><th>ANSWER UPGRADE TABLE</th></tr>\n<tr><td>대시보드 설계</td><td>필터와 페이지네이션을 넣습니다.</td><td>actor/resource/action, 권한별 action, audit event, URL state, server filtering/sorting, cursor pagination, bulk action dry-run을 요구사항과 위험 기준으로 설계합니다.</td></tr>\n<tr><td>대용량 업로드</td><td>파일을 올리고 검증합니다.</td><td>upload session, raw file, parsed row, validation error, domain record를 분리하고 parsing/validation을 job으로 넘겨 queue lag와 worker throughput을 관측합니다.</td></tr>\n<tr><td>출시와 rollback</td><td>단계적으로 배포합니다.</td><td>expand-contract, feature flag, canary, backfill 검증, 구버전 호환성, rollback 불가능 데이터 변경의 forward fix를 설계합니다.</td></tr>\n</table>\n<h3>FOLLOW-UP DEFENSE</h3>\n<table>\n<tr><th>압박 질문</th><th>방어 답변</th><th>COMMON TRAPS</th></tr>\n<tr><td>트래픽이 10배 늘면 어디가 먼저 터지나요?</td><td>QPS 평균보다 peak, read/write ratio, DB connection, queue lag, worker throughput, cache hit ratio를 세우고 bottleneck 후보를 순서대로 좁힙니다.</td><td>서버만 늘리면 된다고 말하기</td></tr>\n<tr><td>설계가 실패하면 어떻게 되돌리나요?</td><td>코드 rollback, schema rollback 가능성, 데이터 migration forward fix, feature flag off, traffic shift를 분리합니다. 데이터 변경은 되돌릴 수 없을 수 있습니다.</td><td>rollback을 배포 취소와 동일시하기</td></tr>\n</table>\n<h3>EVIDENCE TO SAY</h3>\n<p>architecture sketch, capacity sheet, API contract, ERD, sequence diagram, SLO, queue lag dashboard, migration plan, PR·ADR·장애기록·QA ticket을 답변 증거로 준비합니다.</p>\n</section>\n\n<section id=\"doc-project\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>프로젝트 심층 면접</h2></div>\n</section>\n\n<section id=\"project-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-01</span><h2>Q. 가장 복잡했던 프로젝트를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>복잡한 프로젝트 답변은 “큰 프로젝트였습니다”가 아니라 왜 복잡했는지 구조적으로 설명해야 합니다. 도메인 규칙, 데이터 흐름, 상태 전이, API 계약, 검증, 운영 이슈 중 무엇이 어려웠는지 분리합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>프로젝트 심층 답변의 핵심은 규모 자랑이 아니라 복잡성의 원인을 분해하는 것입니다. 도메인 규칙, 상태 전이, 데이터 크기, 팀 경계, 운영 제약 중 무엇이 문제였는지 말해야 면접관이 실제 기여도를 판단할 수 있습니다. 선택의 이유와 버린 대안까지 있어야 경험이 설계 능력으로 들립니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">가장 복잡했던 프로젝트는 단순 화면 구현보다 도메인 규칙이 여러 입력 방식, 검증 단계, API 계약, 결과 화면에 동시에 영향을 준 프로젝트였습니다. 저는 사용자 흐름과 데이터 상태를 먼저 나누고, 입력은 다양해도 내부 모델은 하나로 정규화하며, validation과 저장 실패를 사용자가 회복할 수 있게 설계했습니다.</div>\n<h3>90초 답변</h3><p>답변은 문제, 제약, 구조, 결과 순서로 말합니다. 예를 들어 “Excel 업로드, key-in, grid edit가 서로 다른 입력 채널이지만 최종적으로는 같은 domain row로 저장되어야 했다”처럼 복잡성의 원인을 구체화합니다. 이어서 어떤 상태 구조를 잡았고, 어떤 validation 단계를 나눴고, 어떤 API 변경이나 운영 이슈를 처리했는지 말합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>본인 역할은 정확히 무엇인가요?</td><td>설계, 구현, 리뷰, 운영 대응 중 직접 담당한 범위를 분리합니다.</td></tr><tr><td>어떤 결과가 있었나요?</td><td>정량 수치가 없으면 재사용성, QA 포인트 감소, 오류 위치 명확화 같은 증거를 말합니다.</td></tr><tr><td>다시 한다면?</td><td>초기 모델링, 테스트, 관측, 문서화 중 개선할 지점을 말합니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>도메인 이름과 기능 목록만 나열하지 마세요. 면접관은 “왜 어려웠고 어떻게 구조화했는가”를 듣고 싶어합니다.</p></div>\n</section>\n\n<section id=\"project-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-02</span><h2>Q. Excel, Key-in, Data Grid 입력을 단일 상태로 통합한다는 것은 무엇인가요?</h2></div>\n<h3>핵심 개념</h3><p>입력 채널은 다르지만 저장과 검증의 대상이 되는 도메인 데이터는 하나여야 합니다. channel-specific parsing과 common domain state를 분리합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>서로 다른 입력 채널을 하나로 통합한다는 것은 UI를 하나로 만든다는 뜻이 아니라 저장 가능한 domain row를 하나의 모델로 정규화한다는 뜻입니다. Excel은 parsing과 mapping 문제가 있고, key-in은 즉시 피드백 문제가 있으며, grid edit는 부분 변경과 대량 validation 문제가 있습니다. 공통 모델을 두면 검증과 저장 실패 복구가 같은 규칙을 따릅니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">Excel 업로드, 직접 입력, grid cell edit는 사용자 입장에서는 다른 입력 방식이지만 저장 단계에서는 같은 domain row로 다뤄져야 합니다. 그래서 입력 source는 구분하되 내부에서는 parse, normalize, map을 거쳐 common editable state로 변환하고 validation과 submit은 그 공통 모델 위에서 처리합니다.</div>\n<h3>90초 답변</h3><p>Data Grid column definition은 단순 표시 설정이 아니라 formatter, parser, editor, validator를 가진 계약으로 봅니다. validation은 cell 단위 타입/범위, row 단위 cross-field, submit 단위 중복/서버 의존 규칙으로 나눕니다. 오류는 상단 summary만이 아니라 사용자가 수정할 cell, row, page 위치로 연결되어야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>대용량 grid 성능은?</td><td>virtualization, 변경분 중심 상태, row memoization, debounced validation을 봅니다.</td></tr><tr><td>Excel parsing 실패는?</td><td>template mismatch, header mapping, type 변환, validation 실패를 구분해 보여줍니다.</td></tr><tr><td>dirty check는?</td><td>server snapshot과 draft를 비교하거나 dirty row/cell을 추적합니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“상태를 Redux에 넣었습니다”로 답하지 마세요. 어떤 상태를 왜 분리했는지가 핵심입니다.</p></div>\n</section>\n\n<section id=\"project-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-03</span><h2>Q. Flow Editor의 node/edge 상태는 어떻게 관리했나요?</h2></div>\n<h3>핵심 개념</h3><p>Flow Editor는 화면상의 graph state와 저장 가능한 domain graph를 분리해야 합니다. 사용자의 드래그와 연결선은 UI state이지만 서버에는 도메인 식별자와 관계가 저장됩니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Flow Editor에는 최소 두 개의 graph가 있습니다. 하나는 사용자가 보는 node/edge/position/selection의 view graph이고, 다른 하나는 서버가 저장해야 하는 domain relationship입니다. 이 둘을 분리하지 않으면 화면 이동이나 선택 상태 같은 임시 UI 정보가 도메인 저장 구조를 오염시킵니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">핵심은 domain model과 flow view model을 분리하는 것입니다. 화면에서는 node id, position, selected state, edge source/target이 필요하고, 저장할 때는 도메인 entity id, 관계, 순서, 좌표처럼 복원 가능한 데이터로 변환합니다.</div>\n<h3>90초 답변</h3><p>domain → flow 변환기는 서버 데이터를 화면 노드와 엣지로 만들고, flow → domain 변환기는 사용자가 편집한 그래프를 저장 가능한 payload로 바꿉니다. 성능은 custom node props 안정화, node component memoization, 전체 nodes/edges 배열 구독 최소화, drag 중 업데이트 비용으로 봅니다. 잘못된 연결을 막는 validation도 필요합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>React Flow 성능은?</td><td>custom node 렌더링, props 안정성, selector 분리, viewport rendering을 봅니다.</td></tr><tr><td>저장/불러오기는?</td><td>node id, type, position, edge source/target, 도메인 id를 손실 없이 저장합니다.</td></tr><tr><td>Canvas/SVG/DOM 차이는?</td><td>DOM은 접근성과 구성 쉬움, Canvas는 대량 렌더링, SVG는 벡터와 shape 표현에 유리합니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>라이브러리 사용 여부보다 저장 가능한 구조와 도메인 변환을 설명해야 합니다.</p></div>\n</section>\n\n<section id=\"project-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-04</span><h2>Q. API 전환 프로젝트에서 무엇이 어려웠나요?</h2></div>\n<h3>핵심 개념</h3><p>API 전환은 endpoint만 바꾸는 작업이 아니라 화면이 의존하던 데이터 계약, error handling, loading/empty state, status mapping을 함께 바꾸는 작업입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>API 전환은 endpoint URL을 바꾸는 일이 아니라 데이터 계약을 갈아끼우는 일입니다. status enum, nullable, pagination, error shape가 바뀌면 화면의 조건 분기와 사용자 메시지가 달라집니다. mapping 표와 adapter test를 말하면 단순 연결 작업이 아니라 변경 관리 경험으로 전달됩니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">어려운 점은 response 구조와 status 값이 바뀌면 화면 곳곳의 조건, 표시 문구, action 가능 여부가 함께 바뀐다는 점이었습니다. 그래서 raw response를 직접 쓰지 않고 service/adapter layer에서 view model로 변환해 수정 범위를 줄이는 방향으로 접근했습니다.</div>\n<h3>90초 답변</h3><p>전환할 때는 기존 API와 신규 API의 field mapping, nullable, enum, error format, pagination, 권한 조건을 비교합니다. 화면은 loading, empty, error, permission denied 상태를 모두 가져야 하고, 실패하면 어느 계층 문제인지 Network, service adapter, state update, render layer로 분리해 봅니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>스펙이 불완전하면?</td><td>nullable, enum, error, pagination 질문 목록을 만들고 mock contract로 진행합니다.</td></tr><tr><td>adapter가 과한가요?</td><td>변경 빈도와 화면 모델 차이가 클 때 유용하고, 단순 CRUD에서는 과할 수 있습니다.</td></tr><tr><td>테스트는?</td><td>adapter unit test, API mock integration test, 핵심 화면 E2E를 나눕니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“API 주소만 바꿨습니다”로 들리면 역할이 작아 보입니다. 계약 변경과 화면 영향 분석을 말하세요.</p></div>\n</section>\n\n<section id=\"project-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-05</span><h2>Q. 중복 요청이나 무한 렌더링은 어떻게 디버깅했나요?</h2></div>\n<h3>핵심 개념</h3><p>운영 이슈 답변은 “고쳤다”보다 재현 조건을 좁히고 원인을 계층별로 분리한 과정을 보여줘야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>디버깅 답변은 수정 코드보다 원인을 좁힌 절차가 중요합니다. 중복 요청은 사용자 이벤트, Strict Mode, effect dependency, remount, query key, retry 정책 중 어디서 발생했는지 다르게 대응해야 합니다. 무한 렌더링도 dependency 제거가 아니라 상태 소유권과 effect 책임을 다시 보는 문제입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 재현 조건을 고정하고 Network, Console, React DevTools, state change를 확인합니다. 중복 요청은 Strict Mode, effect dependency, component remount, 버튼 중복 클릭, query key 중복을 보고, 무한 렌더링은 effect가 dependency를 다시 바꾸는지와 매 렌더 새 객체를 만드는지 확인합니다.</div>\n<h3>90초 답변</h3><p>중복 요청은 원인에 따라 대응이 다릅니다. 사용자 중복 클릭이면 in-flight guard나 disabled 처리가 맞고, 검색 요청이면 debounce와 AbortController가 필요할 수 있습니다. 같은 서버 데이터가 여러 컴포넌트에서 호출되면 query key 기반 cache를 봅니다. 무한 렌더링은 dependency를 억지로 제거하기보다 effect의 책임과 state 소유권이 맞는지 봐야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Strict Mode 중복은?</td><td>개발 환경에서 side effect 발견을 위해 두 번 실행될 수 있어 idempotent effect가 필요합니다.</td></tr><tr><td>AbortController는 언제?</td><td>검색/필터처럼 이전 요청 결과가 최신 요청을 덮으면 안 될 때 사용합니다.</td></tr><tr><td>증거는?</td><td>Network waterfall, profiler 캡처, 재현 steps, 수정 전후 로그를 남깁니다.</td></tr></table>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“dependency array를 비웠습니다”는 위험합니다. 왜 그 effect가 필요한지부터 설명해야 합니다.</p></div>\n</section>\n\n<section id=\"project-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-06</span><h2>Q. 복잡한 B2B 도메인을 어떻게 학습했나요?</h2></div>\n<h3>핵심 개념</h3><p>도메인 학습 답변은 열심히 공부했다가 아니라 용어, 규칙, 예외, 사용자 업무 흐름을 어떻게 구조화했는지 보여줘야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>도메인 학습은 문서를 읽었다는 말보다 불확실성을 줄이는 시스템을 만들었다는 말이 강합니다. 용어집, 상태 전이표, validation rule, 예외 케이스, decision log를 만들면 모호한 요구사항이 코드로 흘러들어가는 것을 막을 수 있습니다. 질문을 잘 정리하는 것도 개발 역량의 일부입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 화면과 API 용어를 사용자 업무 용어로 다시 정리하고, 입력-검증-승인-저장-조회 흐름을 그렸습니다. 모호한 규칙은 예시 데이터를 기준으로 질문하고, 결정된 내용은 validation rule과 상태 전이로 문서화했습니다.</div>\n<h3>90초 답변</h3><p>B2B 도메인은 예외가 많기 때문에 단순 요구사항 목록보다 decision log가 중요했습니다. 어떤 값이 필수인지, 어떤 상태에서 수정 가능한지, 권한별 action이 어떻게 다른지 표로 만들고, 화면 상태와 API contract에 반영했습니다. 모르는 부분은 임의 구현하지 않고 질문 목록으로 묶어 빠르게 합의했습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>도메인 전문가와 어떻게 소통?</td><td>예시 데이터와 사용자 시나리오로 질문했습니다.</td></tr><tr><td>문서화는?</td><td>용어집, 상태 전이, validation rule, 예외 케이스를 남겼습니다.</td></tr><tr><td>실수는?</td><td>초기 가정을 작게 만들고 빠르게 검증하는 방식으로 줄였습니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>용어집, rule table, 상태 전이도, 질문 목록, decision log를 준비합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>도메인을 몰랐다는 방어보다 어떻게 학습 시스템을 만들었는지가 중요합니다.</p></div>\n</section>\n\n<section id=\"project-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-07</span><h2>Q. Data Grid column definition을 어떻게 관리했나요?</h2></div>\n<h3>핵심 개념</h3><p>column definition은 표시 설정이 아니라 입력, 변환, 검증, 권한, 저장 payload를 잇는 계약입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>column definition은 UI table 설정이 아니라 입력 계약입니다. formatter는 보여주는 값, parser는 사용자 입력을 도메인 값으로 바꾸는 규칙, validator는 저장 가능성을 판단하는 규칙입니다. 이 계약이 흩어지면 Excel, grid edit, submit validation이 서로 다른 기준으로 움직입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">각 column에 label, accessor, formatter, parser, editor, validator, editable 조건을 정의했습니다. 표시용 값과 저장용 값을 분리하고, Excel import와 key-in 입력도 같은 column contract를 타도록 맞췄습니다.</div>\n<h3>90초 답변</h3><p>column 설정이 화면 곳곳에 흩어지면 validation과 저장 로직이 중복됩니다. 그래서 column definition을 단일 진입점으로 두고 cell edit, Excel mapping, error display가 같은 규칙을 참조하게 했습니다. 다만 너무 범용화하면 복잡해지므로 도메인별 예외는 명시적으로 분리했습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>성능 이슈는?</td><td>column definition 참조 안정성과 cell renderer memoization을 봅니다.</td></tr><tr><td>권한별 편집은?</td><td>editable 조건과 서버 인가를 분리합니다.</td></tr><tr><td>과한 추상화는?</td><td>반복 규칙만 공통화하고 예외는 드러냅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>column schema 예시, parser/validator 테스트, Excel mapping 재사용 사례를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>라이브러리 설정을 잘했다는 답보다 도메인 규칙을 어디에 모았는지가 중요합니다.</p></div>\n</section>\n\n<section id=\"project-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-08</span><h2>Q. validation error를 cell, row, page 단위로 어떻게 보여줬나요?</h2></div>\n<h3>핵심 개념</h3><p>validation UX는 오류를 알려주는 것이 아니라 사용자가 오류 위치로 이동해 수정하고 다시 저장할 수 있게 만드는 흐름입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>validation error UX의 목표는 사용자가 실패를 이해하고 직접 복구할 수 있게 하는 것입니다. cell 오류는 정확한 수정 위치, row 오류는 행 단위 규칙, page summary는 전체 탐색을 담당합니다. 서버 오류도 path와 code가 있어야 UI가 alert가 아니라 수정 가능한 상태로 표현할 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">오류를 field/cell, row, page summary로 나눴습니다. cell 오류는 즉시 수정 위치에 표시하고, row 오류는 cross-field 규칙을 보여주며, page summary는 전체 오류 수와 첫 오류 이동을 제공했습니다.</div>\n<h3>90초 답변</h3><p>서버 오류도 UI가 이해할 수 있는 path로 매핑해야 했습니다. 예를 들어 row id, column key, error code를 받아 grid cell에 연결하고, Excel import 오류도 같은 구조로 표현했습니다. 오류 summary만 보여주면 사용자는 어디를 고쳐야 하는지 몰라 작업 시간이 길어집니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>서버 오류 path가 없으면?</td><td>백엔드와 error contract를 합의하거나 fallback summary를 둡니다.</td></tr><tr><td>대량 오류는?</td><td>필터, 첫 오류 이동, export report를 고려합니다.</td></tr><tr><td>접근성은?</td><td>aria-describedby, focus 이동, 오류 요약을 제공합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>error object 구조, cell highlight, summary 이동, 서버 error contract를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>alert로 오류를 한 번 보여주는 것은 복잡한 입력 UI의 복구 흐름이 아닙니다.</p></div>\n</section>\n\n<section id=\"project-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-09</span><h2>Q. React Flow 성능 문제는 어떻게 봐야 하나요?</h2></div>\n<h3>핵심 개념</h3><p>Flow editor 성능은 노드 수, 커스텀 노드 렌더링, props 안정성, store 구독 범위, drag 중 업데이트 비용으로 나눠 봅니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>React Flow 성능은 라이브러리 문제가 아니라 graph 상태를 어떻게 구독하고 어떤 props를 node에 전달하느냐의 문제일 때가 많습니다. drag 중 전체 graph가 다시 계산되거나 custom node가 새 객체 props를 받아 계속 렌더링되면 체감 성능이 떨어집니다. Profiler 증거와 state 분리 기준을 말해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 Profiler로 어떤 node가 왜 다시 렌더링되는지 확인합니다. custom node props를 안정화하고, 전체 nodes/edges를 넓게 구독하지 않게 하며, drag 중 비싼 계산이나 저장 payload 변환을 분리합니다.</div>\n<h3>90초 답변</h3><p>Flow 화면은 domain graph와 view graph를 분리해야 합니다. 서버 저장용 변환이 매 렌더마다 돌면 비용이 커집니다. node component는 memoization하고, callback과 style 객체를 안정화하며, 선택 상태나 hover 상태가 전체 graph 렌더링을 유발하지 않게 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>저장은 언제?</td><td>사용자 명시 저장 또는 debounce autosave로 렌더와 분리합니다.</td></tr><tr><td>validation은?</td><td>연결 시점의 빠른 검증과 submit 검증을 나눕니다.</td></tr><tr><td>큰 그래프는?</td><td>viewport rendering, clustering, lazy detail을 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>Profiler 캡처, 렌더링 횟수, node/edge 변환 함수, drag 성능 개선 전후를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>React Flow가 느리다고 결론내리기 전에 내 상태 구독과 props 안정성을 확인해야 합니다.</p></div>\n</section>\n\n<section id=\"project-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-10</span><h2>Q. 파일 업로드/다운로드 이슈는 어떻게 해결했나요?</h2></div>\n<h3>핵심 개념</h3><p>파일 기능은 UI 이벤트가 아니라 크기, 타입, 인코딩, 보안, 진행률, 실패 복구, 서버 저장 정책을 포함합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>파일 기능은 브라우저 API 호출이 아니라 입력 신뢰성 문제입니다. 파일 크기, MIME과 실제 내용 불일치, encoding, formula injection, 권한, 다운로드 header가 모두 실패 지점입니다. 업로드와 저장을 분리해 preview/validation 단계를 두면 사용자 복구와 보안 검토가 쉬워집니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">업로드는 파일 크기와 타입 검증, 진행률, 취소, 실패 재시도를 고려했습니다. 다운로드는 filename encoding, content-type, 권한, 대용량 stream, 브라우저 호환성을 확인했습니다.</div>\n<h3>90초 답변</h3><p>Excel이나 CSV는 인코딩과 formula injection, header mismatch 문제가 생길 수 있습니다. 업로드 후 바로 저장하지 않고 preview와 validation 단계를 둬 사용자가 오류를 확인하게 했습니다. 다운로드는 서버가 내려주는 header와 브라우저 처리 차이를 확인해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>대용량 업로드는?</td><td>chunk, presigned URL, progress, resume을 봅니다.</td></tr><tr><td>보안은?</td><td>파일 타입 검증, 악성 수식, 권한, 저장 경로를 봅니다.</td></tr><tr><td>파일명 깨짐은?</td><td>Content-Disposition encoding과 브라우저 호환성을 확인합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>Network header, 파일 검증 규칙, 진행률 UI, 실패 재시도 로그를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>파일 input만 구현했다고 말하면 운영과 보안 고려가 빠져 보입니다.</p></div>\n</section>\n\n<section id=\"project-q11\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-11</span><h2>Q. i18n key와 Storybook은 어떻게 운영했나요?</h2></div>\n<h3>핵심 개념</h3><p>i18n과 Storybook은 문서 도구가 아니라 UI 품질과 변경 관리를 돕는 운영 자산입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>i18n key와 Storybook은 제품 UI의 변경 비용을 낮추는 운영 체계입니다. 번역 key는 언어별 문장 구조를 고려해 설계해야 하고, Storybook은 정상 상태뿐 아니라 loading, empty, error, disabled, permission denied 같은 상태 matrix를 검증하는 장소가 됩니다. 모든 것을 문서화하기보다 반복 컴포넌트와 위험 상태부터 잡는 것이 현실적입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">i18n key는 도메인 namespace로 관리하고, 동적 문장 조합을 줄여 번역 품질을 지켰습니다. Storybook은 컴포넌트 상태 조합, 오류/로딩/빈 상태, 접근성 확인을 위해 사용했습니다.</div>\n<h3>90초 답변</h3><p>번역 key가 화면 문자열과 1:1로만 흩어지면 재사용과 변경 추적이 어렵습니다. Storybook은 디자이너와 QA가 상태를 확인하는 기준점이 되고, interaction test나 accessibility addon을 붙이면 회귀를 빨리 찾을 수 있습니다. 다만 모든 화면을 Storybook화하기보다 재사용 컴포넌트와 복잡한 상태부터 잡는 것이 현실적입니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>missing key는?</td><td>CI check나 runtime report로 추적합니다.</td></tr><tr><td>동적 문장 문제는?</td><td>언어별 어순을 고려해 문장 단위 key를 씁니다.</td></tr><tr><td>Storybook 비용은?</td><td>복잡한 상태와 공통 컴포넌트부터 우선순위를 둡니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>namespace 구조, missing key 리포트, Storybook 상태 matrix, 접근성 addon 결과를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>Storybook을 예쁜 문서로만 보면 품질 검증 도구로서의 가치가 약해집니다.</p></div>\n</section>\n\n<section id=\"project-q12\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-12</span><h2>Q. 프론트엔드 중심 지원자가 백엔드/API 질문을 받으면 어떻게 답하나요?</h2></div>\n<h3>핵심 개념</h3><p>경험의 경계를 지키면서도 API 계약, 데이터 흐름, validation, 장애 진단을 이해한다는 것을 보여줘야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>프론트엔드 중심 지원자가 백엔드 질문을 받을 때 강점은 경계 인식입니다. DB 내부 튜닝을 직접 했다고 과장하기보다 API 계약, 오류 포맷, validation path, pagination, 권한 응답이 사용자 경험에 어떻게 영향을 주는지 정확히 말하는 편이 신뢰를 줍니다. 모르는 영역은 어떤 로그와 지표로 확인할지까지 답하면 됩니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">깊은 백엔드 운영 경험은 제한적일 수 있지만, 프론트 구현에서 API 계약, error format, pagination, 권한, validation 결과를 다뤘고 그 영향이 사용자 흐름에 어떻게 나타나는지 이해하고 있다고 답합니다.</div>\n<h3>90초 답변</h3><p>예를 들어 API response를 그대로 화면에 묶지 않고 adapter로 view model을 만들었고, 서버 validation error를 field/cell 단위로 매핑했으며, 스펙 변경 시 nullable, enum, status code, pagination을 확인했다고 말할 수 있습니다. 모르는 운영 영역은 과장하지 말고 “설계한다면 어떤 지표와 로그로 확인하겠다”까지 답합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>직접 DB 튜닝했나요?</td><td>직접 범위를 말하고 실행 계획/인덱스 개념 이해를 분리합니다.</td></tr><tr><td>백엔드 설계 가능한가요?</td><td>API contract와 데이터 흐름 중심으로 기여 가능 범위를 말합니다.</td></tr><tr><td>운영 경험은?</td><td>로그, trace, 재현 조건, 장애 영향 파악 경험을 말합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>API mapping 표, error contract, Network trace, 백엔드와 합의한 질문 목록을 준비합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>경험을 부풀리기보다 프론트와 서버 경계를 정확히 이해했다는 신뢰를 주는 편이 강합니다.</p></div>\n</section>\n\n<section id=\"project-q13\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-13</span><h2>프로젝트 답변 템플릿</h2></div>\n<p class=\"lede\">프로젝트 심층 면접은 “무엇을 만들었나”보다 “왜 그렇게 판단했고, 무엇을 검증했나”를 봅니다. 답변은 <strong>문제 → 제약 → 선택지 → 선택 이유 → 실패/트레이드오프 → 검증 결과</strong> 순서로 준비합니다.</p>\n<table>\n<tr><th>단계</th><th>말할 내용</th><th>증거 자료</th></tr>\n<tr><td>문제</td><td>사용자나 팀이 실제로 겪은 불편, 비용, 위험</td><td>요구사항, VOC, QA ticket, 장애 기록</td></tr>\n<tr><td>제약</td><td>일정, 기존 API, 브라우저, 데이터 크기, 운영 권한</td><td>스펙 변경 이력, 레거시 구조, 배포 조건</td></tr>\n<tr><td>선택지</td><td>가능했던 대안 2~3개와 버린 이유</td><td>ADR, 회의 메모, PoC 결과</td></tr>\n<tr><td>선택 이유</td><td>팀이 유지할 수 있고 실패 시 복구 가능한 방식</td><td>PR, 설계 문서, 테스트 범위</td></tr>\n<tr><td>실패/트레이드오프</td><td>놓친 점, 성능/복잡도/운영 비용, 다음 개선</td><td>회고, 버그 기록, known limitation</td></tr>\n<tr><td>검증 결과</td><td>전후 수치, 재현 테스트, 사용자 흐름 개선, 운영 안정성</td><td>로그, 지표, E2E, 스크린샷, 릴리즈 노트</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">깊이 파고드는 질문</span>\n<p>“그 선택 말고 다른 방법은?”, “실패하면 어떻게 복구했나요?”, “직접 한 부분은 어디까지인가요?”, “수치가 없으면 어떻게 증명하나요?”를 반드시 준비합니다.</p>\n</div>\n</section>\n\n<section id=\"project-q14\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-14</span><h2>실제 샘플 답변</h2></div>\n<h3>Data Grid 프로젝트</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">90초 샘플</span>\nData Grid 프로젝트에서 어려웠던 점은 Excel 업로드, 직접 입력, cell edit가 서로 다른 입력 경로였지만 최종 저장 모델은 하나여야 했다는 점입니다. 저는 raw input과 domain row를 분리하고, column definition에 parser, formatter, validator를 모아 같은 규칙을 재사용하게 했습니다. validation은 cell, row, submit 단계로 나눴고 서버 오류도 row/cell path로 매핑해 사용자가 바로 수정할 수 있게 했습니다. trade-off는 column definition이 커질 수 있다는 점이었고, 반복 규칙만 공통화하고 도메인 예외는 명시적으로 분리했습니다.\n</div>\n<h3>API 전환 프로젝트</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">90초 샘플</span>\nAPI 전환에서 핵심은 endpoint 교체가 아니라 데이터 계약 변경이었습니다. 기존 화면이 raw response에 강하게 묶여 있으면 nullable, enum, error format 변화가 화면 곳곳을 깨뜨릴 수 있어 service adapter에서 view model로 변환했습니다. 변경 전에는 field mapping, pagination, error code, 권한 조건을 표로 정리했고, MSW mock과 adapter unit test로 화면 영향을 먼저 검증했습니다. 직접 한 범위는 프론트 상태 구조와 adapter, 오류 상태 처리였고 백엔드 내부 구현은 contract 합의 중심으로 협업했습니다.\n</div>\n<h3>React Flow 프로젝트</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">90초 샘플</span>\nReact Flow 프로젝트에서는 domain graph와 view graph를 분리하는 것이 중요했습니다. 서버에는 도메인 id와 관계, 순서, 좌표처럼 복원 가능한 데이터만 저장하고, 화면에서는 selected, dragging, viewport 같은 UI 상태를 따로 관리했습니다. 성능 문제는 Profiler로 custom node가 불필요하게 rerender되는지 확인했고, node props와 callback 참조 안정화, 저장 payload 변환 시점 분리로 대응했습니다. 다시 한다면 처음부터 graph validation과 저장 스키마를 더 명확히 문서화했을 것입니다.\n</div>\n</section>\n\n<section id=\"project-q15\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-15</span><h2>프로젝트 깊이 증거 장부</h2></div>\n<p class=\"lede\">프로젝트 면접은 경험담이 아니라 의사결정의 증거를 검증하는 자리입니다. 직접 한 범위, 제약, 대안, 결과 수치를 분리해 준비해야 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">PROJECT DEPTH LEDGER</span>\n각 프로젝트마다 “문제, 제약, 내가 맡은 범위, 대안, 선택 이유, 실패 모드, 검증 방법, 결과, 배운 점”을 한 장으로 정리합니다. 답변 중에는 팀 성과와 개인 기여를 분리하고, 수치가 없다면 로그, 사용자 피드백, 리뷰 비용, 장애 감소, 운영 시간 감소 같은 간접 근거라도 제시합니다.\n</div>\n<table>\n<tr><th>검증 항목</th><th>면접관이 확인하려는 것</th><th>준비해야 할 답변</th></tr>\n<tr><td>문제 정의</td><td>왜 그 일이 중요했는가?</td><td>사용자 영향, 운영 비용, 매출/전환, 장애 위험 중 하나와 연결합니다.</td></tr>\n<tr><td>제약</td><td>현실적인 조건을 이해했는가?</td><td>일정, 레거시, 데이터 품질, 팀 역량, 배포 위험을 말합니다.</td></tr>\n<tr><td>개인 기여</td><td>직접 한 일이 무엇인가?</td><td>설계, 구현, 테스트, 배포, 모니터링 중 소유 범위를 명확히 합니다.</td></tr>\n<tr><td>대안 비교</td><td>생각 없이 구현하지 않았는가?</td><td>선택지 2개 이상과 포기한 이유를 말합니다.</td></tr>\n<tr><td>실패와 복구</td><td>문제가 생겼을 때 어떻게 다뤘는가?</td><td>장애, 성능 저하, 사용자 혼란, 일정 지연에 대한 대응을 말합니다.</td></tr>\n<tr><td>검증</td><td>성공을 어떻게 확인했는가?</td><td>metric, test, log, QA, 사용자 피드백, 운영 지표를 제시합니다.</td></tr>\n<tr><td>재사용성</td><td>다음 프로젝트에 배운 점을 옮겼는가?</td><td>문서화, 컴포넌트화, runbook, template, lint/test 규칙으로 남긴 것을 말합니다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">오답 방지</span>\n<p>“저희가 개선했습니다”만 반복하면 개인 역량 검증이 어렵습니다. “저는 A를 담당했고, B 대안을 버린 이유는 C였고, 결과는 D 지표로 확인했습니다”처럼 주어와 증거를 분명히 합니다.</p>\n</div>\n</section>\n\n<section id=\"project-q16\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-16</span><h2>프로젝트 핵심 질문 20선</h2></div>\n<p class=\"lede\">프로젝트 면접은 경험의 진짜 깊이를 확인하기 위해 같은 이야기를 문제, 선택, 검증, 실패, 협업 관점에서 반복해 파고듭니다.</p>\n<table>\n<tr><th>축</th><th>구체 질문</th><th>답변 방향</th></tr>\n<tr><td>문제 정의</td><td>이 프로젝트가 해결한 사용자 문제는 정확히 무엇이었나요?</td><td>기능명보다 사용자 불편, 운영 비용, 장애 위험, 매출/전환 영향을 먼저 말합니다.</td></tr>\n<tr><td>개인 기여</td><td>팀 성과 중 본인이 직접 소유한 결정과 구현은 어디까지인가요?</td><td>설계, 구현, 리뷰, 테스트, 배포, 운영 대응 범위를 분리합니다.</td></tr>\n<tr><td>대안 비교</td><td>당시 버린 대안은 무엇이고 왜 버렸나요?</td><td>복잡도, 일정, 운영 위험, 팀 숙련도, rollback 가능성을 기준으로 설명합니다.</td></tr>\n<tr><td>API 계약</td><td>API response가 바뀌었을 때 화면 영향은 어떻게 추적했나요?</td><td>mapping 표, adapter, nullable/enum/error code 검증, mock test를 말합니다.</td></tr>\n<tr><td>상태 관리</td><td>서버 상태, draft 상태, validation 상태를 어떻게 나눴나요?</td><td>원본 snapshot과 변경분, 오류 위치, 저장 실패 복구를 중심으로 말합니다.</td></tr>\n<tr><td>성능</td><td>성능 문제가 있었다면 어떤 지표로 확인했나요?</td><td>Profiler, Network waterfall, 렌더 횟수, API latency, 전후 수치를 제시합니다.</td></tr>\n<tr><td>장애·버그</td><td>가장 어려웠던 버그의 재현 조건과 원인은 무엇이었나요?</td><td>재현 steps, 가설, 로그, 수정 전후 증거를 순서대로 말합니다.</td></tr>\n<tr><td>품질 검증</td><td>성공을 어떤 증거로 확인했나요?</td><td>PR, ADR, metric, QA ticket, 사용자 피드백, before-after 캡처를 연결합니다.</td></tr>\n<tr><td>운영</td><td>배포 후 문제가 생겼을 때 되돌릴 수 있었나요?</td><td>feature flag, rollback, migration 호환성, 모니터링 지표를 말합니다.</td></tr>\n<tr><td>학습</td><td>다시 한다면 무엇을 다르게 하겠나요?</td><td>초기 모델링, 테스트, 관측성, 문서화, 협업 방식 중 하나를 구체화합니다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">압박 꼬리질문</span>\n<p>“그건 팀원이 한 일 아닌가요?”, “수치가 없는데 어떻게 개선을 증명하나요?”, “왜 그 라이브러리를 골랐나요?”, “운영에서 실제로 깨진 적은 없나요?”, “그 결정이 틀렸다면 어떻게 되돌렸나요?”에 개인 주어와 증거로 답합니다.</p>\n</div>\n</section>\n\n<section id=\"project-q17\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-17</span><h2>PROJECT EVIDENCE QUALITY RUBRIC</h2></div>\n<p class=\"lede\">좋은 프로젝트 답변은 기억에 의존하지 않고 검증 가능한 증거를 붙입니다. 증거는 강도가 다르므로 PR, ADR, metric, before-after, 장애기록, QA ticket, 사용자 피드백을 등급별로 준비합니다.</p>\n<table>\n<tr><th>등급</th><th>증거 유형</th><th>면접에서의 신뢰도</th><th>답변 예시</th></tr>\n<tr><td>S</td><td>metric 전후 비교, 장애기록, 운영 dashboard, error/latency 감소, 실제 rollback·postmortem</td><td>성과와 영향이 수치·시간·사용자 범위로 검증됩니다.</td><td>“p95 렌더 시간이 1.8초에서 900ms로 줄었고, 장애기록에는 감지부터 복구까지 타임라인이 남아 있습니다.”</td></tr>\n<tr><td>A</td><td>PR, ADR, 설계 문서, migration plan, release note, 테스트 결과</td><td>의사결정과 구현 범위가 추적됩니다.</td><td>“ADR에는 adapter layer를 둔 이유와 버린 대안이 있고, PR에는 nullable mapping test가 포함되어 있습니다.”</td></tr>\n<tr><td>B</td><td>QA ticket, bug ticket, before-after 스크린샷, 사용자 피드백, CS/VOC</td><td>문제와 개선 흐름은 보이나 정량 영향은 제한적입니다.</td><td>“QA ticket에서 cell error 위치를 찾지 못한다는 이슈가 있었고, 수정 후 같은 케이스가 통과했습니다.”</td></tr>\n<tr><td>C</td><td>회의 메모, Slack 합의, 개인 노트, 질문 목록</td><td>맥락 설명에는 유용하지만 성과 증명으로는 약합니다.</td><td>“도메인 규칙이 모호해 질문 목록으로 정리했고, 합의된 항목을 validation rule table로 옮겼습니다.”</td></tr>\n<tr><td>D</td><td>기억 기반 주장, 기능 목록, 기술 스택 나열</td><td>직접 기여와 결과가 검증되지 않습니다.</td><td>“React Flow를 사용했습니다”가 아니라 “어떤 렌더 병목을 어떤 증거로 줄였는지”로 바꿔야 합니다.</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">EVIDENCE ANSWER TEMPLATE</span>\n“문제는 A였고, 저는 B 결정을 소유했습니다. C 대안을 검토했지만 D 제약 때문에 버렸습니다. 구현은 PR/ADR에 남겼고, 결과는 metric/before-after/QA ticket/사용자 피드백으로 확인했습니다. 운영 중 생긴 문제는 장애기록과 후속 action으로 정리했습니다.”\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">준비 우선순위</span>\n<p>각 프로젝트마다 S/A급 증거 하나와 B급 증거 두 개를 준비합니다. 수치가 없으면 before-after 화면, QA ticket, 사용자 피드백, PR diff, ADR처럼 추적 가능한 자료로 보완하되 “정량 지표는 없었다”고 경계를 분명히 말합니다.</p>\n</div>\n</section>\n\n<section id=\"project-q18\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-18</span><h2>프로젝트 답변 인과관계</h2></div>\n<p class=\"lede\">프로젝트 답변은 사용 기술 목록이 아니라 문제가 있었고, 제약 때문에 선택지가 갈렸고, 내가 선택한 방식이 어떤 결과를 만들었다는 구조여야 합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">PROJECT CAUSAL MODEL</span>면접관은 React, Spring, DB를 썼다는 사실보다 왜 그 문제가 어려웠는지 봅니다. 데이터가 많아서 느렸다면 렌더링 비용인지 네트워크 payload인지 DB query인지 분리해야 하고, 인증 문제가 있었다면 token 만료인지 권한 모델인지 session 동기화인지 나눠야 합니다. 선택 이유는 항상 제약에서 나와야 합니다. “성능 개선을 했다”보다 “대량 grid에서 모든 row를 state로 들고 있어 입력 지연이 생겼고, 변경분 상태와 virtualization으로 render 범위를 줄여 p95 입력 지연을 낮췄다”가 설득력 있습니다.</div>\n<table>\n<tr><th>답변 요소</th><th>부실한 말</th><th>인과관계가 있는 말</th></tr>\n<tr><td>문제 정의</td><td>성능이 느렸습니다</td><td>목록 row 수와 cell editor 수가 늘면서 render와 validation이 같은 tick에 몰렸습니다</td></tr>\n<tr><td>선택 이유</td><td>React Query를 썼습니다</td><td>server state와 form draft state가 섞여 stale overwrite가 발생해 cache invalidation과 optimistic update 경계를 분리했습니다</td></tr>\n<tr><td>검증</td><td>좋아졌습니다</td><td>전후 p95, query count, bundle size, 오류율, 사용자 작업 시간 중 하나를 수치나 재현 절차로 확인했습니다</td></tr>\n<tr><td>트레이드오프</td><td>문제 없었습니다</td><td>선택한 방식이 복잡도를 늘린 지점과 되돌릴 수 있는 조건을 설명했습니다</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">암기 답변 교정</span>\n<p>“제가 담당했습니다”보다 “제가 어떤 제약을 확인했고, 어떤 선택지를 버렸고, 그 결과 어떤 지표나 사용자 흐름이 바뀌었는지”를 말해야 합니다. 증거가 없으면 개선 경험이 아니라 감상으로 들립니다.</p>\n</div>\n</section>\n\n<section id=\"project-project-deep-answer-upgrade\" class=\"answer-card\" data-answer-model=\"definition mechanism tradeoff failure evidence defense\">\n<div class=\"ch-head\"><span class=\"ch-code\">PJ-19</span><h2>DEEP ANSWER MODEL</h2></div>\n<p class=\"lede\">프로젝트 심층 답변은 경험담이 아니라 project depth ledger입니다. 면접관은 personal contribution, trade-off, 실패, 증거를 통해 실제 판단 깊이를 확인합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">CONCEPT DEPTH</span>정의 → 내부 동작 → trade-off → 실패 모드 → 검증 증거 → FOLLOW-UP DEFENSE 순서로 답합니다. 프로젝트 답변에서는 “무엇을 만들었다”보다 “왜 어려웠고, 내가 어떤 결정을 소유했고, 어떤 대안을 버렸고, 결과를 어떤 증거로 확인했는가”가 핵심입니다.</div>\n<table>\n<tr><th>질문</th><th>부실한 답변</th><th>ANSWER UPGRADE TABLE</th></tr>\n<tr><td>대표 프로젝트 설명</td><td>Data Grid와 검색 기능을 만들었습니다.</td><td>대량 row, cell editor, validation, 저장 실패 복구가 문제였고, server snapshot과 draft state를 분리했습니다. trade-off는 상태 구조 복잡도 증가였고, QA ticket 감소와 재현 케이스 통과로 확인했습니다.</td></tr>\n<tr><td>개인 기여</td><td>제가 담당했습니다.</td><td>제가 소유한 결정은 상태 모델과 error mapping이고, 팀은 API와 도메인 규칙을 담당했습니다. 제가 만든 PR, 테스트, 문서, 리뷰 합의로 personal contribution을 구분합니다.</td></tr>\n<tr><td>실패와 개선</td><td>문제 없이 잘 끝났습니다.</td><td>초기에는 수치를 못 남겼고, 대신 QA ticket, before/after 화면, 재현 step, 사용자 피드백을 증거로 정리했습니다. 이후 유사 기능에는 계측과 release note를 먼저 추가했습니다.</td></tr>\n</table>\n<h3>FOLLOW-UP DEFENSE</h3>\n<table>\n<tr><th>압박 질문</th><th>방어 답변</th><th>COMMON TRAPS</th></tr>\n<tr><td>그건 팀원이 한 일 아닌가요?</td><td>본인 결정, 구현, 리뷰, 문서화, 테스트 범위와 팀원이 소유한 API/도메인/운영 영역을 분리해서 답합니다.</td><td>팀 성과 전체를 개인 성과처럼 말하기</td></tr>\n<tr><td>수치가 없는데 성과를 어떻게 증명하나요?</td><td>정량 지표 부재를 인정하고 QA ticket, bug 재현율, before/after, PR diff, 사용자 피드백 같은 대체 증거를 제시합니다.</td><td>개선됐다고만 반복하기</td></tr>\n</table>\n<h3>EVIDENCE TO SAY</h3>\n<p>project depth ledger, PR·ADR·지표·장애기록·QA ticket, before/after 캡처, 재현 step, rejected alternative, personal contribution map을 답변 증거로 준비합니다.</p>\n</section>\n\n<section id=\"doc-personalfull\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>풀스택 개발자 대응</h2></div>\n</section>\n\n<section id=\"personalfull-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-00</span><h2>전략</h2></div>\n<div class=\"serial-card\"><span class=\"sc-label\">POSITIONING</span>저는 프론트엔드 중심이지만 API 계약, 인증/인가, 데이터 조회 조건, 파일 업로드/다운로드, 배포 환경까지 함께 다뤄온 개발자입니다. 서버 구현 자체를 과장하기보다, 서버와 맞닿는 경계에서 사용자 흐름과 데이터 정합성을 어떻게 지켰는지 설명하겠습니다.</div>\n<table>\n<tr><th>풀스택 질문</th><th>앞세울 경험</th></tr>\n<tr><td>API 설계 이해</td><td>검색필터, pagination/filter, 상세 조회, 상태 변경, 파일 업로드/다운로드 API 연동</td></tr>\n<tr><td>인증/인가</td><td>axios interceptor, JWT/refresh token, route guard, 관리자 RBAC, 인증 만료 UX</td></tr>\n<tr><td>데이터 정합성</td><td>금액·수량 정밀도, BigNumber.js, 중복 클릭 방지, 상태 전이 버튼 분기</td></tr>\n<tr><td>운영 흐름</td><td>관리자 콘솔, 서비스 점검 페이지, 환경변수 분리, 배포 스크립트, 오류 응답 처리</td></tr>\n</table>\n</section>\n\n<section id=\"personalfull-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-01</span><h2>서버 경계 경험</h2></div>\n<table>\n<tr><th>경험</th><th>면접 답변 포인트</th></tr>\n<tr><td>axios interceptor</td><td>토큰 부착, 인증 실패 처리, refresh 실패 시 세션 정리, 중복 alert 제거처럼 인증 흐름의 UX와 보안 경계를 설명합니다.</td></tr>\n<tr><td>JWT/refresh token</td><td>access token과 refresh token의 역할, 만료 처리, 재발급 실패 시 요청 복구와 로그아웃 흐름을 말합니다.</td></tr>\n<tr><td>RBAC</td><td>권한 등급별 메뉴 노출, route guard, 접근 불가 페이지, 서버 권한 검증 필요성을 분리해 설명합니다.</td></tr>\n<tr><td>pagination/filter</td><td>URL query, request parameter, 서버 pagination, 필터 초기화, reset 옵션 누락 같은 실무 오류를 설명합니다.</td></tr>\n<tr><td>파일 업로드/다운로드</td><td>S3 업로드, Excel/PDF 다운로드, spinner modal, 파일 크기와 오류 상태, 비동기 처리 가능성을 말합니다.</td></tr>\n<tr><td>실시간/폴링</td><td>스크래퍼 상태 폴링, 디바이스 목록 주기 갱신, WebSocket/STOMP/Socket.IO 경험을 요구사항별로 구분합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"personalfull-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-02</span><h2>답변 템플릿</h2></div>\n<h3>Q. 풀스택 개발자로 볼 수 있는 근거는 무엇인가요?</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">30초</span>서버 구현을 주도한 백엔드 개발자라고 말하기보다는, 프론트엔드에서 서버와 맞닿는 경계를 많이 다뤄온 개발자라고 설명하는 것이 정확합니다. 인증, 권한, API request/response, pagination/filter, 파일 업로드/다운로드, 금액 정밀도, 운영자용 관리 화면을 구현하며 서버 계약과 데이터 흐름을 계속 맞췄습니다.</div>\n<h3>Q. API 계약을 어떻게 다뤘나요?</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">90초</span>목록 화면에서는 query parameter, filter, pagination, sorting, reset 조건을 명확히 맞췄고, 상세/상태 변경 화면에서는 버튼 활성 조건과 API 응답 전 disable 처리로 중복 요청을 막았습니다. 인증이 필요한 요청은 axios interceptor로 token 부착과 만료 처리를 공통화했고, 오류 응답은 사용자가 복구 가능한 위치에 메시지를 노출했습니다.</div>\n<h3>Q. 데이터 정합성을 어떻게 보나요?</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">90초</span>금융성 데이터에서는 JavaScript number만 믿지 않고 BigNumber.js로 소수 정밀도와 금액 표기를 처리했습니다. UI에서는 중복 클릭, 잘못된 상태 전이, 필터 초기화 누락, undefined 값 표시 같은 문제가 실제 정합성 신뢰를 깨뜨리기 때문에 서버 정합성과 별개로 프론트에서도 방어 로직을 둡니다.</div>\n</section>\n\n<section id=\"personalfull-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-03</span><h2>위험한 표현</h2></div>\n<table>\n<tr><th>피해야 할 말</th><th>대체 표현</th></tr>\n<tr><td>“백엔드도 다 할 수 있습니다.”</td><td>“백엔드 실무 구현 경험은 제한적이지만, API 계약과 인증·권한·데이터 흐름은 프론트에서 많이 다뤘고 서버 설계 원리를 학습해 연결하고 있습니다.”</td></tr>\n<tr><td>“DB도 알고 있습니다.”</td><td>“DB는 직접 운영보다 설계 지식 중심입니다. 다만 목록/필터/정렬 API를 다루며 인덱스와 query pattern이 왜 중요한지 이해하고 있습니다.”</td></tr>\n<tr><td>“보안은 token 처리했습니다.”</td><td>“클라이언트 token 처리뿐 아니라 refresh 실패, route guard, 권한별 메뉴, 서버 최종 검증 필요성을 구분해 봅니다.”</td></tr>\n</table>\n</section>\n\n<section id=\"personalfull-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-04</span><h2>학습 연결</h2></div>\n<p class=\"lede\">풀스택 면접에서는 아래 문서와 답변을 연결해서 말합니다.</p>\n<table>\n<tr><th>질문 영역</th><th>연결할 핸드북</th><th>개인화 답변의 연결점</th></tr>\n<tr><td>API·인증</td><td>백엔드·DB 면접, 보안 심화 면접</td><td>JWT/refresh token, RBAC, route guard, server-side authorization</td></tr>\n<tr><td>DB</td><td>DB 심화 면접</td><td>pagination/filter, query pattern, 인덱스, lost update를 UI 정합성 질문과 연결</td></tr>\n<tr><td>운영</td><td>인프라·운영 면접, 클라우드 기본 면접</td><td>환경변수, 배포 스크립트, 서비스 점검 페이지, 오류 응답 처리</td></tr>\n</table>\n</section>\n\n<section id=\"personalfull-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-05</span><h2>강점 전환 문장</h2></div>\n<p class=\"lede\">풀스택 답변의 핵심은 프론트 경험을 그대로 나열하지 않고, 경험을 서버 협업 역량으로 전환해 말하는 것입니다.</p>\n<table>\n<tr><th>프론트 경험</th><th>서버 협업 역량으로 전환</th></tr>\n<tr><td>Data Grid와 검색 필터</td><td>조회 API의 pagination/filter, 정렬 조건, 인덱스 후보를 함께 생각할 수 있습니다.</td></tr>\n<tr><td>인증 만료와 route guard</td><td>JWT/refresh token, 401/403 구분, 서버 최종 권한 검증 필요성을 이해합니다.</td></tr>\n<tr><td>파일 업로드/다운로드</td><td>multipart, presigned URL, 비동기 job, 실패 복구 UX를 API 계약과 연결합니다.</td></tr>\n<tr><td>오류 상태 UI</td><td>서버 error code, retryability, 사용자 복구 가능 메시지의 필요성을 압니다.</td></tr>\n</table>\n<div class=\"serial-card\"><span class=\"sc-label\">ANSWER</span>“제 강점은 서버를 혼자 다 만들었다는 것이 아니라, 프론트에서 서버 계약이 깨지는 지점을 많이 겪었다는 점입니다. 그래서 API 응답 구조, 인증 만료, 권한, pagination/filter, 파일 처리, 오류 복구를 백엔드와 같은 언어로 논의할 수 있습니다.”</div>\n</section>\n\n<section id=\"personalfull-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-06</span><h2>서버 협업 역량</h2></div>\n<p class=\"lede\">풀스택 면접에서는 프론트 경험을 서버 흉내로 바꾸지 말고, 경험을 서버 협업 역량으로 전환해서 말합니다.</p>\n<table>\n<tr><th>프론트 경험</th><th>강점 전환 문장</th></tr>\n<tr><td>목록·필터·pagination</td><td>“목록 화면을 만들 때 서버 query pattern과 사용자의 복원 가능한 검색 조건을 함께 봤기 때문에, API 계약을 화면 상태와 분리해서 생각합니다.”</td></tr>\n<tr><td>인증 만료 UX</td><td>“token refresh를 프론트에서 처리하며 인증 만료, 요청 복구, logout 정리를 다뤘고, 서버에서는 revoke와 rotation이 함께 필요하다고 이해합니다.”</td></tr>\n<tr><td>대량 파일 처리</td><td>“업로드와 다운로드는 UI 이벤트가 아니라 비동기 작업, 오류 응답, 재시도, 진행 상태가 필요한 서버 협업 기능으로 봅니다.”</td></tr>\n<tr><td>금액·수량 표기</td><td>“프론트 표기 정확성을 다루며 서버 계산 결과를 그대로 보여주는 것만으로는 부족하고, decimal precision과 통화/시간대 규칙을 계약에 포함해야 한다는 점을 배웠습니다.”</td></tr>\n</table>\n</section>\n\n<section id=\"personalfull-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">FS-PER-07</span><h2>압박 질문 연결</h2></div>\n<p class=\"lede\">풀스택 포지션에서는 인프라·분산·클라우드·시스템 설계 질문을 “직접 전부 운영했다”로 과장하지 말고, 프론트 경험이 닿은 API 계약과 운영 경계에서 정확히 연결합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">SYSTEM DESIGN PRESSURE DRILL</span>숫자 압박 질문은 DAU, QPS, connection, cache hit ratio, queue lag, worker 수로 가정을 쪼개고, 프론트 경험은 pagination/filter, progress UI, 캐시 가능 조회와 쓰기 경로 분리로 연결합니다.</div>\n<div class=\"serial-card\"><span class=\"sc-label\">DISTRIBUTED CONSISTENCY SENIOR DRILL</span>분산 정합성 질문은 중복 클릭 방지 수준에서 끝내지 않고 idempotency key, outbox/inbox, processed table, reconciliation이 왜 필요한지까지 연결해 답합니다.</div>\n<table>\n<tr><th>압박 질문</th><th>안전한 포지셔닝</th><th>말할 증거</th></tr>\n<tr><td>Kubernetes나 Cloud 운영을 얼마나 이해하나요?</td><td>Service/Ingress, HPA/VPA, PDB, node drain, network policy는 직접 운영 범위를 구분해 설명하고, 배포 중 readiness·rollback·환경변수·로그 확인 경험과 연결합니다.</td><td>배포 스크립트, 환경별 설정, 장애 화면, 릴리즈 확인, 운영자 콘솔 이슈 대응</td></tr>\n<tr><td>IAM, KMS, secret 관리는 어떻게 보나요?</td><td>서버 권한을 직접 설계했다고 과장하지 않고, token/refresh/RBAC 경험에서 IAM trust/resource policy, KMS, secret rotation 필요성을 학습해 연결합니다.</td><td>axios interceptor, 401/403 처리, 권한별 메뉴, secret을 코드에 두지 않은 배포 관행</td></tr>\n<tr><td>분산 정합성 질문을 받으면?</td><td>결제·권한·상태 변경처럼 사용자 신뢰가 큰 경로는 idempotency, 중복 클릭 방지, processed 상태, reconciliation 관점으로 답하고 exactly-once 오해를 피합니다.</td><td>중복 요청 방지, 상태 전이 버튼 제어, API error 재시도 정책, 사용자에게 pending/failed 표시</td></tr>\n<tr><td>시스템 설계 숫자 압박은?</td><td>DAU→QPS→cache hit→DB connection→queue lag→worker 수 순서로 가정을 놓고, 정확한 숫자보다 병목 후보와 질문 목록을 명확히 합니다.</td><td>목록 API pagination/filter, 캐시 가능한 조회와 쓰기 구분, 대량 업로드 job/progress 경험</td></tr>\n<tr><td>프로젝트 증거를 요구하면?</td><td>PROJECT EVIDENCE QUALITY RUBRIC 기준으로 PR/ADR/metric/before-after/장애기록/QA ticket/사용자 피드백 중 실제로 가진 증거만 말합니다.</td><td>PR, QA ticket, before-after 화면, 사용자 피드백, 버그 재현 steps, 수정 전후 로그</td></tr>\n</table>\n<div class=\"serial-card\"><span class=\"sc-label\">ANSWER</span>“풀스택 질문에 답할 때는 제가 직접 운영한 범위와 학습으로 설명할 범위를 나눕니다. 직접 경험은 API 계약, 인증 만료, 권한별 UI, 대량 입력, 오류 복구이고, 여기서 이어지는 서버·인프라 주제는 어떤 지표와 정책을 확인해야 하는지까지 말할 수 있게 준비했습니다.”</div>\n</section>",
};

export default document;
